// ═══ ritual.js ═══
// ── RITUAL TIMER ───────────────────────────────────────────────────────────
// Handles ritual badge display in header, expand/collapse dropdown,
// expiry date calculation, and Snatch News alert tracking.

// ── Utopian date math ────────────────────────────────────────────────────────
// Calendar: 7 months (Jan-Jul), 24 days/month, 168 days/year
// 1 tick = 1 real hour = 1 in-game day

const MONTHS_LIST = [
  'January','February','March','April','May','June','July'
];

/** Convert {month, day, year} to absolute day number (1-based) */
function _utoToAbs(month, day, year) {
  return (year - 1) * 168 + (month - 1) * 24 + day;
}

/** Convert absolute day number back to {month, day, year, label} */
function _absToUto(abs) {
  const y = Math.floor((abs - 1) / 168) + 1;
  const rem = ((abs - 1) % 168);
  const m = Math.floor(rem / 24) + 1;
  const d = (rem % 24) + 1;
  return { year: y, month: m, day: d, label: `${MONTHS_LIST[m-1]} ${d}, YR${y}` };
}

/** Add ticks to current in-game date string "July 18, YR1" → expiry date label */
function _ritualExpiry(currentTickName, ticksRemaining) {
  if (!currentTickName || !ticksRemaining) return null;
  const d = _parseUtoDate(currentTickName);
  if (!d) return null;
  const abs = _utoToAbs(d.month, d.day, d.year) + ticksRemaining;
  return _absToUto(abs);
}

// ── Ritual badge colour ───────────────────────────────────────────────────────
function _ritualColor(ticks) {
  if (ticks == null) return '#7a9090';
  if (ticks <= 24)   return '#ff4455';
  if (ticks <= 48)   return '#ffaa00';
  return '#00ff88';
}

// ── Parse ritual events from kingdomNews.parseString ────────────────────────────
// Works for both own news and SN (enemy news looks identical from their perspective)

function _parseRitualNews(parseString) {
  if (!parseString) return { developing: null, active: null, lifted: null };
  const result = { developing: null, active: null, lifted: null };
  const lines  = parseString.trim().split('\n');

  lines.forEach(line => {
    const parts = line.split('\t');
    if (parts.length < 2) return;
    const dateStr = parts[0].trim();
    const text    = parts[1].trim();
    const d       = _parseNewsDate(dateStr);
    if (!d) return;

    if (/started developing a ritual/i.test(text)) {
      const nm = text.match(/\(([^)]+)\)/);
      // Keep the most recent (last in array = latest in news feed)
      result.developing = { date: d, name: nm ? nm[1] : 'Unknown', dateLabel: dateStr };
    } else if (/ritual is covering/i.test(text)) {
      const nm = text.match(/\(([^)]+)\)/);
      result.active = { date: d, name: nm ? nm[1] : 'Unknown', dateLabel: dateStr };
    } else if (/ritual covering.*lifted/i.test(text)) {
      result.lifted = { date: d, dateLabel: dateStr };
    }
  });

  return result;
}

/** Parse "July 2 of YR1" → {month, day, year} */
function _parseNewsDate(s) {
  const m = s.match(/(\w+)\s+(\d+)\s+of\s+YR(\d+)/i);
  if (!m) return null;
  const idx = MONTHS_LIST.findIndex(n => n.toLowerCase() === m[1].toLowerCase());
  if (idx < 0) return null;
  return { month: idx + 1, day: parseInt(m[2]), year: parseInt(m[3]) };
}

/**
 * Check kingdomNews for enemy ritual development status.
 * Returns null if nothing relevant, or an object with casting info.
 */
function getEnemyRitualCasting() {
  try {
    const IS      = JSON.parse(localStorage.getItem('IntelState') || '{}');
    const news    = IS.kingdomNews?.parseString;
    if (!news) return null;

    const parsed  = _parseRitualNews(news);

    // If no developing entry found → nothing to show
    if (!parsed.developing) return null;

    const dev = parsed.developing;

    // If we have a later "active" entry → ritual already launched, no countdown needed
    if (parsed.active) {
      const devAbs = _utoToAbs(dev.date.month, dev.date.day, dev.date.year);
      const actAbs = _utoToAbs(parsed.active.date.month, parsed.active.date.day, parsed.active.date.year);
      if (actAbs >= devAbs) return null; // launched already
    }

    // If we have a later "lifted" entry after developing → cycle is done
    if (parsed.lifted) {
      const devAbs    = _utoToAbs(dev.date.month, dev.date.day, dev.date.year);
      const liftedAbs = _utoToAbs(parsed.lifted.date.month, parsed.lifted.date.day, parsed.lifted.date.year);
      if (liftedAbs >= devAbs) return null;
    }

    // Ritual is still being cast — calculate auto-launch deadline
    // Auto-launch = start date + 48 ticks
    const startAbs   = _utoToAbs(dev.date.month, dev.date.day, dev.date.year);
    const launchAbs  = startAbs + 48;
    const launchDate = _absToUto(launchAbs);

    // How many ticks until auto-launch? Use current tick date
    let ticksUntilLaunch = null;
    if (S.currentTickName) {
      const cur = _parseUtoDate(S.currentTickName);
      if (cur) {
        const curAbs = _utoToAbs(cur.month, cur.day, cur.year);
        ticksUntilLaunch = launchAbs - curAbs;
      }
    }

    return {
      name:              dev.name,
      startLabel:        dev.dateLabel,
      launchLabel:       launchDate.label,
      ticksUntilLaunch,  // null if we can't calculate, negative if overdue
    };
  } catch(e) {
    return null;
  }
}

// ── Render ritual badges in header ───────────────────────────────────────────
function renderRitualBadges() {
  const own   = S.own?.kdEffects;
  const enemy = S.enemy?.kdEffects;
  const tick  = S.currentTickName;

  let html = '';

  // Own ritual badge
  if (own?.ritual) {
    const col    = _ritualColor(own.ritualDuration);
    const expiry = _ritualExpiry(tick, own.ritualDuration);
    html += `
      <div class="wkb writ-badge" id="__wprit_own" onclick="__wpA.toggleRitual('own')" style="cursor:pointer;border-color:${col}22">
        <div class="l">Own Ritual</div>
        <div class="v" style="color:${col};font-family:monospace">${own.ritualDuration ?? '?'}t</div>
      <div class="writ-drop" id="__wprit_own_drop" style="display:none">
        <div class="writ-drop-title">${esc(own.ritual)}</div>
        <div class="writ-drop-row"><span class="writ-drop-l">Ticks left</span><span style="color:${col};font-family:monospace">${own.ritualDuration ?? '?'}</span></div>
        <div class="writ-drop-row"><span class="writ-drop-l">Real hours</span><span style="font-family:monospace">${own.ritualDuration ?? '?'}h</span></div>
        <div class="writ-drop-row"><span class="writ-drop-l">Effectiveness</span><span style="font-family:monospace;color:#00d4ff">${own.ritualEff?.toFixed(1) ?? '—'}%</span></div>
        ${expiry ? `<div class="writ-drop-row"><span class="writ-drop-l">Expires</span><span style="font-family:monospace;color:#ffaa00">${esc(expiry.label)}</span></div>` : ''}
      </div></div>`;
  }

  // Enemy ritual badge — active ritual OR casting in progress
  const casting = getEnemyRitualCasting();

  if (enemy?.ritual) {
    const col    = _ritualColor(enemy.ritualDuration);
    const expiry = _ritualExpiry(tick, enemy.ritualDuration);
    // Casting info shown inside dropdown even if ritual is already active
    const castingHtml = casting ? `
      <div style="margin-top:10px;padding-top:8px;border-top:1px solid #617070">
        <div style="font-family:monospace;font-size:17px;color:#ffaa00;letter-spacing:1px;margin-bottom:6px">⚠ NEXT RITUAL CASTING</div>
        <div class="writ-drop-row"><span class="writ-drop-l">Ritual</span><span style="font-family:monospace">${esc(casting.name)}</span></div>
        <div class="writ-drop-row"><span class="writ-drop-l">Started</span><span style="font-family:monospace">${esc(casting.startLabel)}</span></div>
        <div class="writ-drop-row"><span class="writ-drop-l">Auto-launch</span><span style="font-family:monospace;color:#ffaa00">${esc(casting.launchLabel)}</span></div>
        ${casting.ticksUntilLaunch != null ? `<div class="writ-drop-row"><span class="writ-drop-l">Time left</span><span style="font-family:monospace;color:${casting.ticksUntilLaunch <= 0 ? '#ff4455' : casting.ticksUntilLaunch <= 12 ? '#ffaa00' : '#ffffff'}">${casting.ticksUntilLaunch <= 0 ? 'OVERDUE — check if launched' : casting.ticksUntilLaunch + 't (' + casting.ticksUntilLaunch + 'h)'}</span></div>` : ''}
      </div>` : '';
    const castingSubline = casting
      ? `<div style="font-family:monospace;font-size:13px;color:#ffaa00;margin-top:2px;line-height:1">⚗ ${
          casting.ticksUntilLaunch != null
            ? (casting.ticksUntilLaunch <= 0 ? 'OVERDUE' : casting.ticksUntilLaunch + 't')
            : '?'
        }</div>`
      : '';
    html += `
      <div class="wkb writ-badge" id="__wprit_ene" onclick="__wpA.toggleRitual('ene')" style="cursor:pointer;border-color:${col}22">
        <div class="l">Enemy Ritual</div>
        <div class="v" style="color:${col};font-family:monospace">${enemy.ritualDuration ?? '?'}t</div>
        ${castingSubline}
      <div class="writ-drop" id="__wprit_ene_drop" style="display:none">
        <div class="writ-drop-title">${esc(enemy.ritual)}</div>
        <div class="writ-drop-row"><span class="writ-drop-l">Ticks left</span><span style="color:${col};font-family:monospace">${enemy.ritualDuration ?? '?'}</span></div>
        <div class="writ-drop-row"><span class="writ-drop-l">Real hours</span><span style="font-family:monospace">${enemy.ritualDuration ?? '?'}h</span></div>
        <div class="writ-drop-row"><span class="writ-drop-l">Effectiveness</span><span style="font-family:monospace;color:#00d4ff">${enemy.ritualEff?.toFixed(1) ?? '—'}%</span></div>
        ${expiry ? `<div class="writ-drop-row"><span class="writ-drop-l">Expires</span><span style="font-family:monospace;color:#ffaa00">${esc(expiry.label)}</span></div>` : ''}
        ${castingHtml}
      </div></div>`;
  } else if (casting) {
    // No active ritual but casting detected — show amber badge
    const timeCol = casting.ticksUntilLaunch != null && casting.ticksUntilLaunch <= 12 ? '#ff4455' : '#ffaa00';
    const timeStr = casting.ticksUntilLaunch != null
      ? (casting.ticksUntilLaunch <= 0 ? 'OVERDUE' : casting.ticksUntilLaunch + 't')
      : '?';
    html += `
      <div class="wkb writ-badge" id="__wprit_ene" onclick="__wpA.toggleRitual('ene')" style="cursor:pointer;border-color:#ffaa0022">
        <div class="l">Enemy Casting</div>
        <div class="v" style="color:${timeCol};font-family:monospace">⚠ ${timeStr}</div>
      <div class="writ-drop" id="__wprit_ene_drop" style="display:none">
        <div class="writ-drop-title" style="color:#ffaa00">⚠ Ritual Being Cast</div>
        <div class="writ-drop-row"><span class="writ-drop-l">Ritual</span><span style="font-family:monospace">${esc(casting.name)}</span></div>
        <div class="writ-drop-row"><span class="writ-drop-l">Started</span><span style="font-family:monospace">${esc(casting.startLabel)}</span></div>
        <div class="writ-drop-row"><span class="writ-drop-l">Auto-launch</span><span style="font-family:monospace;color:#ffaa00">${esc(casting.launchLabel)}</span></div>
        ${casting.ticksUntilLaunch != null ? `<div class="writ-drop-row"><span class="writ-drop-l">Time left</span><span style="font-family:monospace;color:${timeCol}">${casting.ticksUntilLaunch <= 0 ? 'OVERDUE — check if launched' : casting.ticksUntilLaunch + 't (' + casting.ticksUntilLaunch + 'h)'}</span></div>` : ''}
        <div style="margin-top:8px;font-size:17px;color:#7a9090">Source: Snatch News. Take another SN to confirm if it has launched.</div>
      </div></div>`;
  }

  const container = $id('__wprit');
  if (container) container.innerHTML = html;
}

/** Toggle ritual dropdown open/closed */
function toggleRitual(which) {
  const drop = $id(`__wprit_${which}_drop`);
  if (!drop) return;
  const isOpen = drop.style.display !== 'none';
  // Close all dropdowns first
  ['own','ene'].forEach(w => {
    const d = $id(`__wprit_${w}_drop`);
    if (d) d.style.display = 'none';
  });
  if (!isOpen) drop.style.display = 'block';
}

// ── Snatch News alert ────────────────────────────────────────────────────────
// Stored in Firebase: meta/{kdId}_sn_ack — {ackedAt: timestamp}
// Alert fires if more than 24h since last ack

async function snAck() {
  const kdId = S.own?.location.replace(':', '_');
  if (!kdId) return;
  await fbWrite(`meta/${kdId}_sn_ack`, { ackedAt: Date.now(), ackedBy: S.own?.kingdomName || '' });
  renderAlerts(); // refresh alerts to clear the SN alert
}

async function getSnLastAck() {
  const kdId = S.own?.location.replace(':', '_');
  if (!kdId) return 0;
  try {
    const doc = await fbGet(`meta/${kdId}_sn_ack`);
    if (doc?.fields?.ackedAt) return parseInt(doc.fields.ackedAt.integerValue || 0);
  } catch(e) {}
  return 0;
}

// Expose SN last-ack time on S so alerts can check it synchronously
// Updated once on init and after each ack
async function loadSnAck() {
  S.snLastAck = await getSnLastAck();
}


// ═══ discord.js ═══
// ── DISCORD ────────────────────────────────────────────────────────────────
// Sends rich embed alerts to a Discord channel via webhook.
// Webhook URL stored in war plan. Alert state stored in Firebase.
// Only fires when alert status CHANGES since last check.

const DISCORD = {
  COUNCIL_ROLE:   '1397235789980631165',
  ATTACKER_ROLE:  '1503879181291753593',
  COLORS: {
    red:    16711680,  // #FF0000
    yellow: 16776960,  // #FFFF00
    green:  65280,     // #00FF00
  },
};

// ── Webhook send ─────────────────────────────────────────────────────────────

async function sendDiscordEmbed(webhookUrl, { content, embeds }) {
  if (!webhookUrl) return false;
  try {
    const r = await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: content || '', embeds }),
    });
    if (!r.ok) console.warn('[WavePlanner] Discord webhook failed:', r.status);
    return r.ok;
  } catch(e) {
    console.warn('[WavePlanner] Discord webhook error:', e.message);
    return false;
  }
}

// ── Alert state helpers ───────────────────────────────────────────────────────

async function loadAlertState() {
  const kdId = S.own?.location.replace(':', '_');
  if (!kdId) return {};
  try {
    const doc = await fbGet(`meta/${kdId}_alert_state`);
    if (!doc?.fields) return {};
    // Unwrap Firestore format — values stored as JSON strings
    const state = {};
    Object.entries(doc.fields).forEach(([k, v]) => {
      try { state[k] = JSON.parse(v.stringValue || 'null'); }
      catch(e) { state[k] = null; }
    });
    return state;
  } catch(e) { return {}; }
}

async function saveAlertState(state) {
  const kdId = S.own?.location.replace(':', '_');
  if (!kdId) return;
  // Store each value as a JSON string
  const data = {};
  Object.entries(state).forEach(([k, v]) => { data[k] = JSON.stringify(v); });
  await fbWrite(`meta/${kdId}_alert_state`, data);
}

// ── Main alert check ──────────────────────────────────────────────────────────

async function checkAndSendDiscordAlerts() {
  const webhookUrl = S.discordWebhook;
  if (!webhookUrl) return;
  if (!S.own) return;

  const prev = await loadAlertState();
  const next  = {};
  const toSend = []; // array of {content, embeds, _key} — _key marks which next[] entry to revert on send failure

  // ── 1. Dragon on own KD — does not need enemy data ────────────────────
  const ownDragon = S.own.kdEffects?.dragon || '';
  next.dragon_own = ownDragon;
  if (ownDragon && ownDragon !== (prev.dragon_own || '')) {
    toSend.push({
      _key: 'dragon_own',
      content: '@everyone',
      embeds: [{
        title: '🐉 Dragon incoming',
        description: `A **${ownDragon}** is now ravaging our lands!`,
        color: DISCORD.COLORS.red,
        timestamp: new Date().toISOString(),
        footer: { text: 'Wave Planner · War Planning Tool' },
      }],
    });
  }

  // ── Own food low — does not need enemy data ────────────────────────────
  const foodThr = S.thresholds.ownFoodLow || 0;
  if (foodThr > 0) {
    const lowFood = (S.own.provinces || [])
      .filter(p => p.sot && p.sot.food != null && p.sot.food < foodThr)
      .map(p => ({ name: p.name, food: p.sot.food }));
    next.own_food_low = lowFood.map(p => p.name);
    const prevLowFood = prev.own_food_low || [];
    const newLowFood  = lowFood.filter(p => !prevLowFood.includes(p.name));
    if (newLowFood.length) {
      const foodLines = newLowFood.map(p => `· ${p.name} — ${fK(p.food)} food`).join('\n');
      toSend.push({
        _key: 'own_food_low',
        content: '',
        embeds: [{
          title: `🍞 Own food critical — ${newLowFood.length} province${newLowFood.length > 1 ? 's' : ''}`,
          description: foodLines,
          color: DISCORD.COLORS.red,
          footer: { text: 'Send aid immediately · Wave Planner' },
          timestamp: new Date().toISOString(),
        }],
      });
    }
  } else {
    next.own_food_low = [];
  }

  // ── Own peons low — does not need enemy data ───────────────────────────
  const peasThr = S.thresholds.ownPeasLow || 0;
  if (peasThr > 0) {
    const lowPeas = (S.own.provinces || [])
      .filter(p => {
        const peas = p.sot?.peasants ?? p.sot?.peons;
        return peas != null && peas > 0 && peas < peasThr;
      })
      .map(p => ({ name: p.name, peas: p.sot?.peasants ?? p.sot?.peons }));
    next.own_peas_low = lowPeas.map(p => p.name);
    const prevLowPeas = prev.own_peas_low || [];
    const newLowPeas  = lowPeas.filter(p => !prevLowPeas.includes(p.name));
    if (newLowPeas.length) {
      const peasLines = newLowPeas.map(p => `· ${p.name} — ${fK(p.peas)} peasants`).join('\n');
      toSend.push({
        _key: 'own_peas_low',
        content: '',
        embeds: [{
          title: `👥 Own population critical — ${newLowPeas.length} province${newLowPeas.length > 1 ? 's' : ''}`,
          description: peasLines,
          color: DISCORD.COLORS.red,
          footer: { text: 'Check for starvation or hostile spells · Wave Planner' },
          timestamp: new Date().toISOString(),
        }],
      });
    }
  } else {
    next.own_peas_low = [];
  }

  // ── War end detection → auto-post war summary ─────────────────────────────
  // Track whether we were at war last check. When it flips from true → false,
  // compile and post a war summary embed before the state is overwritten.
  const curAtWar = _atWar();
  next.war_active = curAtWar;
  if (prev.war_active === true && !curAtWar) {
    await _postWarSummary(webhookUrl);
  }

  // ── Enemy-dependent checks — skip and preserve prev state if not loaded ─
  if (S.enemy) {
    // ── Dragon slayed on enemy ───────────────────────────────────────────
    const eneDragon = S.enemy.kdEffects?.dragon || '';
    next.dragon_enemy = eneDragon;
    const prevEneDragon = prev.dragon_enemy || '';
    if (!eneDragon && prevEneDragon) {
      toSend.push({
        _key: 'dragon_enemy',
        content: `<@&${DISCORD.COUNCIL_ROLE}>`,
        embeds: [{
          title: '⚔️ Enemy dragon gone',
          description: `The enemy **${prevEneDragon}** is no longer active.\nConfirm via SoT.`,
          color: DISCORD.COLORS.red,
          timestamp: new Date().toISOString(),
          footer: { text: 'Wave Planner · War Planning Tool' },
        }],
      });
    }

    // ── Intel age helper ─────────────────────────────────────────────────
    // Returns "(intel Xm old)" string or "" — mirrors the alerts tab display.
    function _ageTag(p) {
      const s = p?.calcs?.defPointsSummary?.ageSeconds;
      return s != null ? ` (intel ${fA(s)} old)` : '';
    }

    // ── Missing SoM (new provinces only) ─────────────────────────────────
    const missingSom = (S.enemy.provinces || [])
      .filter(p => (p.sot?.opa || 0) > 80 && !p.som)
      .map(p => p.name);
    next.missing_som = missingSom;
    const prevMissing = prev.missing_som || [];
    const newMissing  = missingSom.filter(n => !prevMissing.includes(n));
    if (newMissing.length) {
      const missingLines = newMissing.map(name => {
        const p = S.enemy?.provinces?.find(p => p.name === name);
        const opa = p?.sot?.opa || 0;
        return `· ${name}${opa ? ' (' + opa + ' OPA)' : ''}${_ageTag(p)}`;
      }).join('\n');
      toSend.push({
        _key: 'missing_som',
        content: `<@&${DISCORD.ATTACKER_ROLE}>`,
        embeds: [{
          title: `⚠️ Missing SoM — ${newMissing.length} province${newMissing.length > 1 ? 's' : ''}`,
          description: missingLines,
          color: DISCORD.COLORS.yellow,
          footer: { text: 'Take a SoM on these before the next wave · Wave Planner' },
          timestamp: new Date().toISOString(),
        }],
      });
    }

    // ── Enemy food rich ───────────────────────────────────────────────────
    const foodRichThr = S.thresholds.enemyFoodRich || 0;
    if (foodRichThr > 0) {
      const richFood = (S.enemy.provinces || [])
        .filter(p => p.sot && p.sot.food != null && p.sot.food > foodRichThr)
        .map(p => ({ name: p.name, food: p.sot.food, age: _ageTag(p) }));
      next.enemy_food_rich = richFood.map(p => p.name);
      const newRichFood = richFood.filter(p => !(prev.enemy_food_rich || []).includes(p.name));
      if (newRichFood.length) {
        toSend.push({
          _key: 'enemy_food_rich',
          content: `<@&${DISCORD.ATTACKER_ROLE}>`,
          embeds: [{
            title: `🍞 Enemy food target — ${newRichFood.length} province${newRichFood.length > 1 ? 's' : ''}`,
            description: newRichFood.map(p => `· ${p.name} — ${fK(p.food)} food${p.age}`).join('\n') + '\nUse steal food / vermin.',
            color: DISCORD.COLORS.yellow,
            footer: { text: `Threshold: ${fK(foodRichThr)} · Wave Planner` },
            timestamp: new Date().toISOString(),
          }],
        });
      }
    } else { next.enemy_food_rich = []; }

    // ── Enemy food low / starvation risk ─────────────────────────────────
    const foodLowThr = S.thresholds.enemyFoodLow || 0;
    if (foodLowThr > 0) {
      const starveProv = (S.enemy.provinces || [])
        .filter(p => p.sot && p.sot.food != null && p.sot.food < foodLowThr)
        .map(p => ({ name: p.name, food: p.sot.food, age: _ageTag(p) }));
      next.enemy_food_low = starveProv.map(p => p.name);
      const newStarve = starveProv.filter(p => !(prev.enemy_food_low || []).includes(p.name));
      if (newStarve.length) {
        toSend.push({
          _key: 'enemy_food_low',
          content: `<@&${DISCORD.ATTACKER_ROLE}>`,
          embeds: [{
            title: `💀 Enemy starvation risk — ${newStarve.length} province${newStarve.length > 1 ? 's' : ''}`,
            description: newStarve.map(p => `· ${p.name} — only ${fK(p.food)} food${p.age}`).join('\n') + '\nUse vermin + drought + gluttony.',
            color: DISCORD.COLORS.red,
            footer: { text: `Threshold: ${fK(foodLowThr)} · Wave Planner` },
            timestamp: new Date().toISOString(),
          }],
        });
      }
    } else { next.enemy_food_low = []; }

    // ── Enemy GC rich ─────────────────────────────────────────────────────
    const gcRichThr = S.thresholds.enemyGcRich || 0;
    if (gcRichThr > 0) {
      const richGc = (S.enemy.provinces || [])
        .filter(p => p.sot && p.sot.money != null && p.sot.money > gcRichThr)
        .map(p => ({ name: p.name, gc: p.sot.money, age: _ageTag(p) }));
      next.enemy_gc_rich = richGc.map(p => p.name);
      const newRichGc = richGc.filter(p => !(prev.enemy_gc_rich || []).includes(p.name));
      if (newRichGc.length) {
        toSend.push({
          _key: 'enemy_gc_rich',
          content: `<@&${DISCORD.ATTACKER_ROLE}>`,
          embeds: [{
            title: `💰 Enemy GC target — ${newRichGc.length} province${newRichGc.length > 1 ? 's' : ''}`,
            description: newRichGc.map(p => `· ${p.name} — ${fK(p.gc)} GC${p.age}`).join('\n') + '\nUse fools gold / steal gold.',
            color: DISCORD.COLORS.yellow,
            footer: { text: `Threshold: ${fK(gcRichThr)} · Wave Planner` },
            timestamp: new Date().toISOString(),
          }],
        });
      }
    } else { next.enemy_gc_rich = []; }

    // ── Enemy runes rich ──────────────────────────────────────────────────
    const runesRichThr = S.thresholds.enemyRunesRich || 0;
    if (runesRichThr > 0) {
      const richRunes = (S.enemy.provinces || [])
        .filter(p => p.sot && p.sot.runes != null && p.sot.runes > runesRichThr)
        .map(p => ({ name: p.name, runes: p.sot.runes, age: _ageTag(p) }));
      next.enemy_runes_rich = richRunes.map(p => p.name);
      const newRichRunes = richRunes.filter(p => !(prev.enemy_runes_rich || []).includes(p.name));
      if (newRichRunes.length) {
        toSend.push({
          _key: 'enemy_runes_rich',
          content: `<@&${DISCORD.ATTACKER_ROLE}>`,
          embeds: [{
            title: `🔮 Enemy runes target — ${newRichRunes.length} province${newRichRunes.length > 1 ? 's' : ''}`,
            description: newRichRunes.map(p => `· ${p.name} — ${fK(p.runes)} runes${p.age}`).join('\n') + '\nUse lightning strike / steal runes.',
            color: DISCORD.COLORS.yellow,
            footer: { text: `Threshold: ${fK(runesRichThr)} · Wave Planner` },
            timestamp: new Date().toISOString(),
          }],
        });
      }
    } else { next.enemy_runes_rich = []; }

  } else {
    // Enemy not loaded — carry forward previous enemy state so we don't
    // lose track of what was already alerted and avoid false re-fires later.
    next.dragon_enemy     = prev.dragon_enemy     || '';
    next.missing_som      = prev.missing_som      || [];
    next.enemy_food_rich  = prev.enemy_food_rich  || [];
    next.enemy_food_low   = prev.enemy_food_low   || [];
    next.enemy_gc_rich    = prev.enemy_gc_rich    || [];
    next.enemy_runes_rich = prev.enemy_runes_rich || [];
  }

  // ── Send all queued alerts ─────────────────────────────────────────────
  // For each message: if the send fails, revert that state key to its previous
  // value so the alert retries on the next tool open instead of being lost.
  const savedNext = { ...next };
  let sentCount = 0;
  for (const { _key, content, embeds } of toSend) {
    const ok = await sendDiscordEmbed(webhookUrl, { content, embeds });
    if (ok) {
      sentCount++;
    } else if (_key) {
      savedNext[_key] = prev[_key] ?? null; // revert — will retry next open
    }
    await new Promise(r => setTimeout(r, 500));
  }

  // ── Save new state ────────────────────────────────────────────────────
  await saveAlertState(savedNext);

  if (sentCount) console.log(`[WavePlanner] Sent ${sentCount}/${toSend.length} Discord alert(s)`);
  if (sentCount < toSend.length) console.warn(`[WavePlanner] ${toSend.length - sentCount} alert(s) failed — will retry on next open`);
}

// ── War summary post ──────────────────────────────────────────────────────────
// Called when war_active transitions true → false. Pulls ops from Firebase,
// compiles per-player stats, and posts a single summary embed.

async function _postWarSummary(webhookUrl) {
  try {
    const kdId = S.own?.location.replace(':', '_');
    if (!kdId || !webhookUrl) return;

    // War period from kingdomNews (gives in-game date range)
    const period = _getWarPeriod();

    // Fetch all ops for this KD from Firebase
    const allOps = await fbQuery('ops', [{ field: 'kingdomId', value: kdId }]);

    // Filter to the war period if we could detect one
    let warOps = allOps;
    if (period) {
      warOps = allOps.filter(op => {
        const ym = _ym(op.utoYear || 0, op.utoMonth || 0);
        if (!ym && op.utoDate) {
          const d = _parseUtoDate(op.utoDate);
          if (d) {
            const opYm = _ym(d.year, d.month);
            return opYm >= _ym(period.fromYear, period.fromMonth) && opYm <= _ym(period.toYear, period.toMonth);
          }
        }
        return ym >= _ym(period.fromYear, period.fromMonth) && ym <= _ym(period.toYear, period.toMonth);
      });
    }

    // Aggregate per player
    const byPlayer = {};
    warOps.forEach(op => {
      if (!op.provinceName) return;
      if (!byPlayer[op.provinceName]) byPlayer[op.provinceName] = { ops: 0, success: 0, damage: 0, gain: 0 };
      const p = byPlayer[op.provinceName];
      p.ops++;
      if (op.success) p.success++;
      p.damage += op.damage || 0;
      p.gain   += op.gain   || 0;
    });

    const totalOps    = warOps.length;
    const totalSucc   = warOps.filter(o => o.success).length;
    const totalDamage = warOps.reduce((s, o) => s + (o.damage || 0), 0);
    const totalGain   = warOps.reduce((s, o) => s + (o.gain   || 0), 0);
    const successRate = totalOps > 0 ? Math.round(totalSucc / totalOps * 100) : 0;

    // Top performers sorted by op count
    const players = Object.entries(byPlayer)
      .map(([name, s]) => ({ name, ...s }))
      .sort((a, b) => b.ops - a.ops)
      .slice(0, 10);

    const topLines = players.map((p, i) => {
      const rate   = p.ops > 0 ? Math.round(p.success / p.ops * 100) : 0;
      const dmgStr = p.damage > 0 ? ` · ${fK(p.damage)} dmg` : '';
      const gainStr= p.gain   > 0 ? ` · +${fK(p.gain)} acres` : '';
      return `${i + 1}. **${p.name}** — ${p.ops} ops (${rate}%)${dmgStr}${gainStr}`;
    }).join('\n');

    const durationLine = period
      ? `${period.fromLabel} → ${period.toLabel}`
      : 'Duration unknown';

    const lines = [
      `**vs ${S.enemy?.kingdomName || S.eLoc || 'Enemy KD'}**  ·  ${durationLine}`,
      '',
      `**${totalOps}** ops  ·  **${successRate}%** success rate`,
      totalDamage ? `**${fK(totalDamage)}** total damage dealt` : null,
      totalGain   ? `**+${fK(totalGain)}** total land gained` : null,
    ].filter(l => l !== null);

    if (players.length) {
      lines.push('', '**Top performers:**', topLines);
    } else {
      lines.push('', '_No op data recorded for this war._');
    }

    await sendDiscordEmbed(webhookUrl, {
      content: `<@&${DISCORD.COUNCIL_ROLE}>`,
      embeds: [{
        title: '⚔️ War ended — Summary',
        description: lines.join('\n'),
        color: DISCORD.COLORS.green,
        timestamp: new Date().toISOString(),
        footer: { text: 'Wave Planner · War Summary' },
      }],
    });

    console.log('[WavePlanner] War summary posted to Discord');
  } catch(e) {
    console.warn('[WavePlanner] War summary post failed:', e.message);
  }
}

// ── Reset Discord alert state ─────────────────────────────────────────────────
// Clears all saved state so every active condition fires again on next check.

async function resetDiscordAlertState() {
  const kdId = S.own?.location.replace(':', '_');
  if (!kdId) return;
  await fbWrite(`meta/${kdId}_alert_state`, {});
  console.log('[WavePlanner] Discord alert state cleared');
}

// ── Test ping ─────────────────────────────────────────────────────────────────

async function testDiscordWebhook(webhookUrl) {
  if (!webhookUrl) return false;
  return sendDiscordEmbed(webhookUrl, {
    content: '',
    embeds: [{
      title: '✅ Wave Planner connected',
      description: 'Discord alerts are working correctly.',
      color: 65280,
      timestamp: new Date().toISOString(),
      footer: { text: 'Wave Planner · War Planning Tool' },
    }],
  });
}


// ═══ tabs/board.js ═══
// ── TAB: BOARD ─────────────────────────────────────────────────────────────
// War board — sortable table of enemy provinces with wave assignment,
// ops panel, raze/massacre tracking, and notes.
// Replaces the old kanban drag-and-drop interface.

// ── Sort state ────────────────────────────────────────────────────────────────
// S.boardSort = { col: 'slot', dir: 1 }

function boardSort(col) {
  if (!S.boardSort) S.boardSort = { col: 'slot', dir: 1 };
  if (S.boardSort.col === col) { S.boardSort.dir *= -1; }
  else { S.boardSort.col = col; S.boardSort.dir = -1; }
  renderBoard();
}

// ── Province plan helpers ─────────────────────────────────────────────────────

/** Get or create the plan entry for a province slot */
function _pp(slot) {
  if (!S.provinces[slot]) {
    S.provinces[slot] = { wave: null, assignedTo: [], bloat: false, needsRaze: false, needsMassacre: false, requiredOps: [], notes: '' };
  }
  // Migrate legacy entries that predate assignedTo / bloat
  if (!Array.isArray(S.provinces[slot].assignedTo)) S.provinces[slot].assignedTo = [];
  if (S.provinces[slot].bloat === undefined)        S.provinces[slot].bloat = false;
  return S.provinces[slot];
}

function setProvWave(slot, wave) {
  _pp(slot).wave = wave || null;
  renderBoard();
  renderSummary();
  renderPlayer();
}

function setProvNeedsRaze(slot, val) {
  _pp(slot).needsRaze = val;
  renderBoard();
}

function setProvNeedsMassacre(slot, val) {
  _pp(slot).needsMassacre = val;
  renderBoard();
}

function setProvBloat(slot, val) {
  _pp(slot).bloat = val;
  renderBoard();
  renderPlayer();
}

// ── Assignment picker ─────────────────────────────────────────────────────────
// _assignPickerSlot tracks which row's picker is open (UI state, not persisted)
let _assignPickerSlot = null;

function toggleAssignPicker(slot) {
  _assignPickerSlot = _assignPickerSlot === slot ? null : slot;
  renderBoard();
}

function toggleProvAssign(slot, name, checked) {
  const plan = _pp(slot);
  if (checked && !plan.assignedTo.includes(name)) {
    plan.assignedTo.push(name);
  } else if (!checked) {
    plan.assignedTo = plan.assignedTo.filter(n => n !== name);
  }
  renderBoard();
  renderPlayer();
}

// ── Render ────────────────────────────────────────────────────────────────────

function renderBoard() {
  // Inject board-row hover style once per page load
  if (!document.getElementById('__wp_board_style')) {
    const st = document.createElement('style');
    st.id = '__wp_board_style';
    st.textContent = '.wp-brow:hover{background:#3c4545!important}';
    document.head.appendChild(st);
  }
  renderTab('__wpc_board', _buildBoard);
}

function _buildBoard() {
  if (!S.enemy) return `
    <div class="webar">
      <label>ENEMY:</label>
      <input id="__wpeloc" value="${esc(S.eLoc)}" placeholder="5:3">
      <button class="wb" style="font-size:17px"
        onclick="__wpA.loadEnemy(document.getElementById('__wpeloc').value);__wpA.refresh()">
        LOAD
      </button>
    </div>
    <div class="wload">NO ENEMY LOADED</div>`;

  if (!S.boardSort) S.boardSort = { col: 'slot', dir: 1 };

  // Build row data from enemy provinces
  const rows = S.enemy.provinces.map(p => {
    const sot  = p.sot || {};
    const surv = p.survey;
    const plan = _pp(p.slot);
    const da   = p.calcs?.defPointsSummary?.ageSeconds;
    const ppa  = sot.ppa || 0;
    const popPct = Math.min(Math.round(ppa / 25 * 100), 150); // cap display at 150%
    const nwpa   = p.land > 0 ? Math.round((p.networth || 0) / p.land) : 0;
    const rtpa   = p.land > 0 && sot.rTpa != null ? sot.rTpa
                 : p.land > 0 && sot.thieves != null ? +(sot.thieves / p.land).toFixed(2)
                 : null;
    const castles = surv?.buildings?.find(b => b.name === 'Castles')?.pctTot || null;
    const wt      = surv?.buildings?.find(b => b.name === 'Watch Towers')?.pctTot || null;
    return {
      slot: p.slot, name: p.name, race: p.race || '—',
      nw: p.networth || 0, land: p.land || 0, nwpa,
      popPct, off: sot.offPoints || 0,
      def: p.calcs?.defPointsSummary?.defPointsHome || sot.defPoints || 0,
      rtpa, castles, wt,
      intelAge: da,
      wave:          plan.wave,
      assignedTo:    plan.assignedTo    || [],
      bloat:         plan.bloat         || false,
      needsRaze:     plan.needsRaze,
      needsMassacre: plan.needsMassacre,
      requiredOps:   plan.requiredOps   || [],
      notes:         plan.notes         || '',
    };
  });

  // Sort
  const { col, dir } = S.boardSort;
  rows.sort((a, b) => {
    let av = a[col], bv = b[col];
    // Nulls to bottom regardless of sort direction
    if (av == null && bv == null) return 0;
    if (av == null) return 1;
    if (bv == null) return -1;
    if (typeof av === 'string') return dir * av.localeCompare(bv);
    return dir * (av - bv);
  });

  // Sort indicator
  const si = c => S.boardSort.col === c
    ? `<span style="color:#ffd400;margin-left:3px;">${S.boardSort.dir === -1 ? '↓' : '↑'}</span>`
    : `<span style="color:#617070;margin-left:3px;">⇅</span>`;

  const thStyle = (c, right=false) => `cursor:pointer;user-select:none;white-space:nowrap;padding:8px 10px;
    text-align:${right?'right':'left'};background:#2b3333;font-size:15px;font-weight:700;
    letter-spacing:1px;text-transform:uppercase;border-bottom:1px solid #617070;
    color:${S.boardSort.col===c?'#ffd400':'#7a9090'};`;

  const th  = (c, l, right=false) => `<th onclick="__wpA.boardSort('${c}')" style="${thStyle(c,right)}">${l}${si(c)}</th>`;
  const thS = (l) => `<th style="${thStyle('',false)}color:#7a9090;">${l}</th>`; // static header

  // Wave badge colours
  const waveBadge = (wave) => {
    if (wave === 'current')   return `<span style="background:rgba(224,80,80,.15);color:#E05050;border:1px solid #8B1414;font-size:15px;padding:2px 7px;border-radius:2px;white-space:nowrap;">Current Wave</span>`;
    if (wave === 'current 1') return `<span style="background:rgba(224,80,80,.22);color:#ff7070;border:1px solid #c01414;font-size:15px;padding:2px 7px;border-radius:2px;white-space:nowrap;">Current P1</span>`;
    if (wave === 'current 2') return `<span style="background:rgba(224,80,80,.12);color:#e05050;border:1px solid #8B1414;font-size:15px;padding:2px 7px;border-radius:2px;white-space:nowrap;">Current P2</span>`;
    if (wave === 'preplan')   return `<span style="background:rgba(212,160,23,.12);color:#ffd400;border:1px solid #7a6500;font-size:15px;padding:2px 7px;border-radius:2px;white-space:nowrap;">Pre-Plan</span>`;
    return `<span style="color:#617070;font-size:17px;">—</span>`;
  };

  const isLeader = S.role === 'leader';

  const tableRows = rows.map(r => {
    const ageCol = r.intelAge == null ? '#617070'
                 : r.intelAge < 3600  ? '#60C040'
                 : r.intelAge < 14400 ? '#ffd400'
                 : r.intelAge < 28800 ? '#e09040' : '#E05050';

    const popCol = r.popPct >= 100 ? '#60C040' : r.popPct >= 75 ? '#ffd400' : '#E05050';

    const waveSelect = isLeader ? `
      <select onchange="__wpA.setProvWave(${r.slot},this.value)"
        style="background:#2b3333;border:1px solid #617070;color:#ffffff;font-size:17px;
               padding:3px 6px;border-radius:3px;outline:none;cursor:pointer;max-width:120px;">
        <option value=""         ${!r.wave                   ?'selected':''}>—</option>
        <option value="current"  ${r.wave==='current'        ?'selected':''}>Current Wave</option>
        <option value="current 1"${r.wave==='current 1'      ?'selected':''}>Current P1</option>
        <option value="current 2"${r.wave==='current 2'      ?'selected':''}>Current P2</option>
        ${r.wave==='preplan'?`<option value="preplan" selected>Pre-Plan (legacy)</option>`:''}
      </select>` : waveBadge(r.wave);

    const razeCheck = isLeader
      ? `<input type="checkbox" ${r.needsRaze?'checked':''} onchange="__wpA.setProvNeedsRaze(${r.slot},this.checked)"
           style="cursor:pointer;width:14px;height:14px;accent-color:#ffd400;">`
      : r.needsRaze ? '✓' : '—';

    const massCheck = isLeader
      ? `<input type="checkbox" ${r.needsMassacre?'checked':''} onchange="__wpA.setProvNeedsMassacre(${r.slot},this.checked)"
           style="cursor:pointer;width:14px;height:14px;accent-color:#ffd400;">`
      : r.needsMassacre ? '✓' : '—';

    const bloatCheck = isLeader
      ? `<input type="checkbox" ${r.bloat?'checked':''} onchange="__wpA.setProvBloat(${r.slot},this.checked)"
           style="cursor:pointer;width:14px;height:14px;accent-color:#9060c0;">`
      : r.bloat ? '<span style="color:#9060c0">✓</span>' : '—';

    // Assignment picker — own province multi-select
    const ownProvNames = (S.own?.provinces || []).map(p => p.name);
    const isPickerOpen = _assignPickerSlot === r.slot;
    const safeSlot     = r.slot;
    const assignTags   = r.assignedTo.length === 0
      ? '<span style="color:#617070;font-size:15px">KD pool</span>'
      : r.assignedTo.map(n => `<span class="wtag" style="font-size:13px;margin:1px;cursor:default">${esc(n)}</span>`).join('');
    const assignCell = isLeader
      ? `<div class="wp-assign-wrap" onclick="event.stopPropagation()">
           <div class="wp-assign-btn" onclick="__wpA.toggleAssignPicker(${safeSlot})">${assignTags}</div>
           ${isPickerOpen ? `<div class="wp-assign-drop">
             <div class="wp-assign-drop-hd">
               <span style="font-size:15px;font-weight:700;color:#7a9090;letter-spacing:1px;text-transform:uppercase">Assign to</span>
               <span onclick="__wpA.toggleAssignPicker(${safeSlot})" style="cursor:pointer;color:#7a9090;font-size:19px;line-height:1;padding:0 4px">✕</span>
             </div>
             ${ownProvNames.length
               ? ownProvNames.map(name => {
                   const safeName = name.replace(/\\/g,'\\\\').replace(/'/g,"\\'");
                   return `<label class="wp-assign-item">
                     <input type="checkbox" ${r.assignedTo.includes(name)?'checked':''}
                       onchange="__wpA.toggleProvAssign(${safeSlot},'${safeName}',this.checked)">
                     <span>${esc(name)}</span>
                   </label>`;
                 }).join('')
               : '<div style="font-size:17px;color:#617070;padding:4px">No own provinces loaded</div>'
             }
           </div>` : ''}
         </div>`
      : `<div>${assignTags}</div>`;

    const opTags = r.requiredOps.length
      ? r.requiredOps.map(o => `<span class="wtag" style="cursor:default;font-size:15px;">${o}</span>`).join('')
      : '';

    return `<tr class="wp-brow${r.bloat?' wp-bloat-row':''}" style="border-bottom:1px solid rgba(97,112,112,.25);${r.wave?.startsWith('current')&&!r.bloat?'background:rgba(224,80,80,.04);':r.wave==='preplan'&&!r.bloat?'background:rgba(212,160,23,.03);':''}">
      <td style="padding:7px 10px;font-weight:700;color:#ffffff;">${r.slot}</td>
      <td style="padding:7px 10px;color:#ffffff;font-weight:500;max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">
        <span onclick="__wpA.openOps(${r.slot})" style="cursor:pointer;" title="Click to assign ops">${esc(r.name)}</span>
        ${opTags ? `<div style="margin-top:2px;">${opTags}</div>` : ''}
        ${r.notes ? `<div style="font-size:17px;color:#7a9090;font-style:italic;margin-top:1px;">${esc(r.notes.substring(0,40))}${r.notes.length>40?'…':''}</div>` : ''}
      </td>
      <td style="padding:7px 10px;color:#7a9090;font-size:17px;">${esc(r.race)}</td>
      <td style="padding:7px 10px;text-align:right;">${fK(r.nw)}</td>
      <td style="padding:7px 10px;text-align:right;">${fK(r.land)}</td>
      <td style="padding:7px 10px;text-align:right;">${fK(r.nwpa)}</td>
      <td style="padding:7px 10px;text-align:right;color:${popCol};font-weight:600;">${r.popPct}%</td>
      <td style="padding:7px 10px;text-align:right;">${fK(r.off)}</td>
      <td style="padding:7px 10px;text-align:right;">${fK(r.def)}</td>
      <td style="padding:7px 10px;text-align:right;">${r.rtpa != null ? r.rtpa.toFixed(2) : '—'}</td>
      <td style="padding:7px 10px;text-align:right;">${r.castles != null ? r.castles.toFixed(1)+'%' : '—'}</td>
      <td style="padding:7px 10px;text-align:right;">${r.wt != null ? r.wt.toFixed(1)+'%' : '—'}</td>
      <td style="padding:7px 10px;text-align:right;font-size:17px;color:${ageCol};">${r.intelAge != null ? fA(r.intelAge) : '—'}</td>
      <td style="padding:7px 10px;text-align:center;">${waveSelect}</td>
      <td style="padding:5px 7px;vertical-align:middle;">${assignCell}</td>
      <td style="padding:7px 10px;text-align:center;color:${r.bloat?'#9060c0':'#7a9090'};">${bloatCheck}</td>
      <td style="padding:7px 10px;text-align:center;color:${r.needsRaze?'#ffd400':'#7a9090'};">${razeCheck}</td>
      <td style="padding:7px 10px;text-align:center;color:${r.needsMassacre?'#ffd400':'#7a9090'};">${massCheck}</td>
    </tr>`;
  }).join('');

  // Summary counts
  const assigned   = rows.filter(r => r.wave?.startsWith('current')).length;
  const bloatCount = rows.filter(r => r.bloat).length;
  const preplanned = rows.filter(r => r.wave === 'preplan').length;

  const enemyBar = `
    <div class="webar">
      <label>ENEMY:</label>
      <input id="__wpeloc" value="${esc(S.eLoc)}" placeholder="5:3">
      <button class="wb" style="font-size:17px"
        onclick="__wpA.loadEnemy(document.getElementById('__wpeloc').value);__wpA.refresh()">
        LOAD
      </button>
      <div style="color:#ffd400;font-weight:700;font-size:19px">${esc(S.enemy?.kingdomName || '—')}</div>
      <div style="font-size:17px;color:#7a9090;margin-left:auto">
        ${rows.length} provinces ·
        <span style="color:#E05050;">${assigned} wave targets</span>
        ${bloatCount ? ` · <span style="color:#9060c0">${bloatCount} bloat</span>` : ''}
        ${preplanned ? ` · <span style="color:#ffd400">${preplanned} pre-plan</span>` : ''}
      </div>
    </div>`;

  const table = `
    <div style="overflow-x:auto;">
      <table style="width:100%;border-collapse:collapse;font-size:19px;background:#3c4545;border:1px solid #617070;border-radius:4px;overflow:hidden;">
        <thead><tr>
          ${th('slot','#')}
          ${th('name','Province')}
          ${th('race','Race')}
          ${th('nw','NW',true)}
          ${th('land','Acres',true)}
          ${th('nwpa','NW/Ac',true)}
          ${th('popPct','Pop%',true)}
          ${th('off','Off',true)}
          ${th('def','Def',true)}
          ${th('rtpa','rTPA',true)}
          ${th('castles','Castle%',true)}
          ${th('wt','WT%',true)}
          ${th('intelAge','Intel',true)}
          ${thS('Wave')}
          ${thS('Assigned')}
          ${thS('Bloat')}
          ${thS('Raze')}
          ${thS('Mass.')}
        </tr></thead>
        <tbody>${tableRows}</tbody>
      </table>
    </div>`;

  return enemyBar + table + _buildOpsPanel();
}

// ── Ops panel (modal overlay) ──────────────────────────────────────────────────

function _buildOpsPanel() {
  return `<div class="wops" id="__wpops"></div>`;
}

function openOps(slot) {
  S.openSlot = slot;
  const p    = S.enemy?.provinces?.find(p => p.slot === slot);
  const plan = _pp(slot);
  const ops  = plan.requiredOps || [];
  const sot  = p?.sot || {};
  const da   = p?.calcs?.defPointsSummary?.ageSeconds;

  const html = `
    <div class="wopsh">
      <h3>// OPS — Slot ${slot}</h3>
      <button onclick="__wpA.closeOps()" style="background:none;border:none;color:#7a9090;cursor:pointer;font-size:21px">✕</button>
    </div>
    <div class="wopsb">
      <div style="font-size:21px;font-weight:700;margin-bottom:3px;color:#ffffff;">${esc(p?.name || 'Unknown')}</div>
      <div style="font-size:17px;color:#7a9090;margin-bottom:12px;">
        ${esc(p?.race || '')} · ${esc(sot.personality || '')} · Slot ${slot}
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:10px">
        <div class="wsb"><div class="l">OPA</div><div class="v">${sot.opa || '—'}</div></div>
        <div class="wsb"><div class="l">DPA</div><div class="v">${sot.dpa || '—'}</div></div>
        <div class="wsb"><div class="l">Def Home</div><div class="v">${fK(p?.calcs?.defPointsSummary?.defPointsHome)}</div></div>
        <div class="wsb"><div class="l">Intel Age</div><div class="v"><span class="${aC(da)}">${fA(da)}</span></div></div>
      </div>
      ${sot.badSpells?.length ? `<div style="font-size:17px;color:#E05050;margin-bottom:8px;">⚠ ${sot.badSpells.map(s=>s.name).join(', ')}</div>` : ''}
      ${p?.som?.armiesAway?.length ? `<div style="font-size:17px;color:#60C040;margin-bottom:8px;">↗ Army away — ${fA(p.som.armiesAway[0].secondsRemaining)} to return</div>` : ''}
      <div class="wopsec">Duration Ops</div>
      <div class="wopsg">
        ${DOPS.map(o => `<div class="wop${ops.includes(o.c)?' sel':''}" onclick="__wpA.togOp(${slot},'${o.c}')" title="${esc(o.l)}">${esc(o.c)}</div>`).join('')}
      </div>
      <div class="wopsec">Instant Ops</div>
      <div class="wopsg">
        ${IOPS.map(o => `<div class="wop i${ops.includes(o.c)?' sel':''}" onclick="__wpA.togOp(${slot},'${o.c}')" title="${esc(o.l)}">${esc(o.c)}</div>`).join('')}
      </div>
      <div class="wopsec">Notes</div>
      <textarea style="width:100%;background:#2b3333;border:1px solid #617070;color:#ffffff;font-size:17px;padding:6px;border-radius:2px;resize:vertical;min-height:60px;outline:none;"
        onblur="__wpA.setNote(${slot},this.value)">${esc(plan.notes || '')}</textarea>
    </div>`;

  const panel = $id('__wpops');
  if (panel) { panel.innerHTML = html; panel.classList.add('open'); }
}

function closeOps() {
  const panel = $id('__wpops');
  if (panel) panel.classList.remove('open');
  S.openSlot = null;
}

function togOp(slot, c) {
  const plan = _pp(slot);
  if (!plan.requiredOps) plan.requiredOps = [];
  const idx = plan.requiredOps.indexOf(c);
  if (idx >= 0) plan.requiredOps.splice(idx, 1);
  else          plan.requiredOps.push(c);
  // renderBoard replaces the whole board HTML — the manual DOM update below was
  // redundant (immediately overwritten). Keep only the re-render.
  renderBoard();
}

function setNote(slot, v) {
  _pp(slot).notes = v;
}

/** Legacy: seed from old kanban cols format on first load */
function initCols() {
  if (!S.enemy) return;
  // If we have old kanban data, migrate it
  if (S.cols?.length > 0) {
    S.cols.forEach((col, ci) => {
      col.items?.forEach(item => {
        const slot = parseInt((item.province.slot + '').replace(/\[|\]/g, ''));
        if (!slot) return;
        const plan = _pp(slot);
        if (ci > 0 && !plan.wave) plan.wave = ci === 1 ? 'current' : 'preplan';
        if (item.province.requiredOps?.length) plan.requiredOps = item.province.requiredOps;
        if (item.province.notes) plan.notes = item.province.notes;
      });
    });
    S.cols = []; // clear legacy data
  }
  // Ensure all enemy provinces have a plan entry
  S.enemy.provinces.forEach(p => _pp(p.slot));
}

// ── Legacy stubs (kept so old save format doesn't crash) ────────────────────
function boardDragStart() {}
function boardDrop() {}
function addCol() {}
function delCol() {}
function rmOp(ci, ii, c) {
  // Legacy — find by position in old cols
  const item = S.cols[ci]?.items[ii];
  if (!item) return;
  const slot = parseInt((item.province.slot+'').replace(/\[|\]/g,''));
  const ops  = _pp(slot).requiredOps || [];
  const i    = ops.indexOf(c);
  if (i >= 0) ops.splice(i, 1);
  renderBoard();
}


// ═══ tabs/player.js ═══
// ── TAB: PLAYER ────────────────────────────────────────────────────────────

// ── Standalone TM gain estimator ────────────────────────────────────────────
// Extracted so calcMaxGainAttacks() can also call it with simulated state.
// S.enemy?.kdEffects is read from global state (stable within a session).
function _estimateTMGain(tNW, tLand, tp, ownLand, aNW, ownKdAvgNW, eneKdAvgNW) {
  if (!tLand || !ownLand || !tNW || !aNW) return null;

  const rpnw = tNW / aNW;
  let rpnwF = 0;
  if      (rpnw >= 0.567 && rpnw < 0.9)  rpnwF = 3 * rpnw - 1.7;
  else if (rpnw >= 0.9   && rpnw <= 1.1) rpnwF = 1;
  else if (rpnw >  1.1   && rpnw <= 1.6) rpnwF = -2 * rpnw + 3.2;
  if (rpnwF <= 0) return 0;

  const rknw  = ownKdAvgNW > 0 ? eneKdAvgNW / ownKdAvgNW : 1;
  const rknwF = rknw < 0.5 ? 0.8 : rknw < 0.9 ? rknw / 2 + 0.55 : 1;

  const mapText  = tp?.sot?.map || '';
  const mapF     = (!mapText || mapText === 'Not much') ? 1.0
                 : mapText === 'A little'               ? 0.90
                 : 0.80;

  const castlePct = tp?.survey?.buildings?.find(b => b.name === 'Castles')?.pctTot;
  const castleF   = castlePct != null ? Math.max(0, 1 - (castlePct / 100 * 2.25)) : 1.0;

  const relF = 1.10;

  let enemyRitualF = 1.0;
  const eRitual = (S.enemy?.kdEffects?.ritual || '').toLowerCase();
  if (eRitual.includes('protection') || eRitual.includes('shield') || eRitual.includes('barrier')) {
    const eff = S.enemy?.kdEffects?.ritualEff || 15;
    enemyRitualF = Math.max(0.5, 1 - eff / 100);
  }

  const raw = tLand * 0.12 * rpnwF * rknwF * relF * mapF * castleF * enemyRitualF;
  const cap = Math.min(ownLand, tLand) * 0.20;
  return Math.round(Math.min(raw, cap));
}
// "My Orders" tab — province picker + attack plan calculator.
// calcAttacks() is pure business logic, separated from the render function.

// ── Manual stat overrides (per province, persisted in localStorage) ─────────
// Players enter their own max off / NW / generals rather than relying on
// potentially stale SoM/SoT API data.

function _mkey(provName) { return 'wc_ms_' + provName; }

function loadManual(provName) {
  try { return JSON.parse(localStorage.getItem(_mkey(provName)) || '{}'); }
  catch(e) { return {}; }
}

function saveManual(provName, obj) {
  localStorage.setItem(_mkey(provName), JSON.stringify(obj));
}

/** Called by inline oninput handlers — saves a single field and re-renders. */
function setManualStat(provName, field, rawVal) {
  var ms = loadManual(provName);
  var v  = parseInt(rawVal);
  if (v > 0) ms[field] = v; else delete ms[field];
  saveManual(provName, ms);
  renderPlayer();
}

/** Return the effective value for a stat: manual override > API data > 0 */
function _eff(provName, field, apiVal) {
  var ms = loadManual(provName);
  return ms[field] != null ? ms[field] : (apiVal || 0);
}

// ── Raze / Massacre claim storage (per war, per device) ──────────────────────
// Stored as { "raze_18": "My Province", "massacre_5": "My Province" }
// Key is scoped to enemy location so it resets each new war automatically.

function _claimKey() { return 'wc_raze_' + (S.eLoc || ''); }
function loadClaims() {
  try { return JSON.parse(localStorage.getItem(_claimKey()) || '{}'); }
  catch(e) { return {}; }
}

/** Toggle a raze/massacre claim for a slot. Called from inline onclick. */
function claimAction(slot, type) {
  const c = loadClaims();
  const k = type + '_' + slot;
  if (c[k]) delete c[k]; else c[k] = S.playerProv?.name || '✓';
  localStorage.setItem(_claimKey(), JSON.stringify(c));
  renderPlayer();
}

/**
 * Parse wave string → numeric priority for sorting.
 * 'current 1' → 1, 'current 2' → 2, 'current' (no number) → 50
 */
function _waveOrder(wave) {
  if (!wave) return 999;
  if (wave === 'current') return 50;
  if (wave.startsWith('current ')) {
    const n = parseInt(wave.split(' ')[1]);
    return isNaN(n) ? 50 : n;
  }
  return 50;
}

/** Human-readable wave name for attack card headers */
function _waveDisplayName(wave) {
  if (wave === 'current')   return 'Current Wave';
  if (wave === 'current 1') return 'Current Wave P1';
  if (wave === 'current 2') return 'Current Wave P2';
  if (wave === 'preplan')   return 'Pre-Plan';
  return wave || 'Wave';
}

/**
 * Pure function: given a province, return an ordered attack plan.
 *
 * Key mechanics:
 *  - attackableGens = gensHome - 1   (1 general ALWAYS stays home)
 *  - Offense and generals are TWO INDEPENDENT pools:
 *      offLeft  starts at aOff, depleted by (target_def + 1) per attack
 *      gensLeft starts at attackableGens, depleted by N per attack
 *  - Normally 1 general per attack; extra generals only when offLeft ≤ tDef,
 *    each adds 5% to offense: effective = offLeft × (1 + 0.05×(N−1))
 *  - Assigned RAZE/MASS → single hit each (war leader flag always honoured)
 *  - Assigned TM → multi-hit loop with min gens until can't break or gens/off gone
 *  - KD pool uses remaining gens/off; pop% strategy determines types
 *  - Bloat targets never TM — only raze/mass when flagged by war leader
 *  - Gains estimated for TM attacks using RPNW × RKNW × modifiers
 *
 * Returns {attacks, gensHome, attackableGens, gensLeft, offLeft,
 *          ownPop, totalGains, reason}
 */
function calcAttacks(prov) {
  // ── Own stats with army-return auto-correction ────────────────────────────
  // armiesAway[i].secondsRemaining <= 0 means that army is past its return window.
  // When ALL armies are overdue, offPointsHome and standingArmy.generals are stale.
  //
  // Fix: SoT offPoints = total offense for ALL troops regardless of location,
  // so it's the best available "all generals home" figure.
  // SoT generals = total province generals (same logic).
  // Manual overrides still take full priority via _eff().

  const _armiesAway   = prov.som?.armiesAway || [];
  const _overdueCount = _armiesAway.filter(
    a => a.secondsRemaining != null && a.secondsRemaining <= 0
  ).length;
  const _anyArmyAway  = _armiesAway.length > 0;
  const _allOverdue   = _anyArmyAway && _overdueCount === _armiesAway.length;
  const _anyOverdue   = _anyArmyAway && _overdueCount > 0;

  // Offense: prefer SoT total when all armies are overdue
  const _sotOff  = prov.sot?.offPoints || 0;
  const _apiOff  = _allOverdue && _sotOff ? _sotOff : (prov.som?.offPointsHome || 0);
  const _offSrc  = _allOverdue && _sotOff  ? 'sot'
                 : _allOverdue && !_sotOff ? 'stale'  // overdue but no SoT — show warning
                 : 'som';

  // Generals: prefer SoT total when all armies are overdue
  const _sotGens = prov.sot?.generals;
  const _apiGens = _allOverdue && _sotGens != null
    ? _sotGens
    : (prov.som?.standingArmy?.generals ?? _sotGens ?? 5);
  const _gensSrc = _allOverdue && _sotGens != null ? 'sot' : 'som';

  // Bundle for UI display
  const armyStatus = {
    anyAway:    _anyArmyAway,
    anyOverdue: _anyOverdue,
    allOverdue: _allOverdue,
    offSrc:     _offSrc,   // 'som' | 'sot' | 'stale'
    gensSrc:    _gensSrc,  // 'som' | 'sot'
  };

  const aOff     = _eff(prov.name, 'off',  _apiOff);
  const aNW      = _eff(prov.name, 'nw',   prov.networth || 0);
  const gensHome = _eff(prov.name, 'gens', _apiGens);
  const ownLand  = prov.land || prov.sot?.acres || 0;

  // Fix: always keep 1 general home
  const attackableGens = Math.max(0, gensHome - 1);

  // Own pop% — Utopia formula:
  //   Current Population = peasants + totalTroops + thieves + wizards
  //   Raw Living Space   = builtAcres*25 + barrenAcres*15 + homesAcres*35  (survey used when available)
  //   Mod Living Space   = Raw × Race Bonus × (1 + Housing Science %)
  //   Pop%               = Current Population / Mod Living Space * 100
  // Race: Halfling ×1.10, Faery ×0.95, others ×1.00  (source: age_details)
  // Housing science: sos.books[{type:'Housing'}].effect (e.g. 4.5 → ×1.045)
  // Honor pop bonus: not available in province data — treated as ×1.0
  // sot.ppa is peasants-per-acre only, NOT total people — don't use it directly.
  const _sot  = prov.sot || {};
  const _land = prov.land || _sot.land || 0;
  const _totalPop = (_sot.peasants || 0) + (_sot.totalTroops || 0)
                  + (_sot.thieves  || 0) + (_sot.wizards    || 0);

  // Race population multiplier
  const _racePopMult = (function(race) {
    if (!race) return 1;
    const r = race.toLowerCase();
    if (r === 'halfling') return 1.10;
    if (r === 'faery')    return 0.95;
    return 1;
  })(prov.race);

  let ownPop = null;
  if (_land > 0) {
    const _bArr = prov.survey?.buildings;
    let _rawLS;
    if (_bArr && _bArr.length > 0) {
      // Survey available — accurate living space
      const _barrenEntry = _bArr.find(b => /barren/i.test(b.name));
      const _homesEntry  = _bArr.find(b => /^homes$/i.test(b.name));
      const _sumBuilt    = _bArr
        .filter(b => !(/barren/i.test(b.name)))
        .reduce((s, b) => s + (b.pctTot || 0), 0);
      const _barrenPct   = _barrenEntry ? (_barrenEntry.pctTot || 0) : Math.max(0, 100 - _sumBuilt);
      const _homesPct    = _homesEntry  ? (_homesEntry.pctTot  || 0) : 0;
      const _barrenAcres = _land * _barrenPct / 100;
      const _homesAcres  = _land * _homesPct  / 100;
      const _builtAcres  = _land - _barrenAcres - _homesAcres;
      _rawLS = _builtAcres * 25 + _barrenAcres * 15 + _homesAcres * 35; // Homes = 25 built + 10 bonus
    } else {
      // No survey — simplified fallback
      _rawLS = _land * 25;
    }
    // Housing science bonus: sos.books[{type:'Housing', effect:N}] → +N% max pop
    const _housingEffect = prov.sos?.books?.find(b => b.type === 'Housing')?.effect || 0;
    const _scienceMult   = 1 + (_housingEffect / 100);
    // Honor population bonus: not available in province data — treated as 1.0
    const _modLS = _rawLS * _racePopMult * _scienceMult;
    ownPop = _modLS > 0
      ? Math.min(Math.round(_totalPop / _modLS * 100), 150)
      : null;
  }

  if (!aOff)          return { attacks: [], gensHome, attackableGens, ownPop, reason: 'no_off' };
  if (!attackableGens) return { attacks: [], gensHome, attackableGens, ownPop, reason: 'no_gens' };

  // ── Helpers: generals and offense are independent pools ───────────────────
  // Min gens to break tDef given current offLeft:
  //   1 gen if offLeft > tDef (normal case)
  //   N gens if extra bonus needed: offLeft × (1 + 0.05×(N−1)) > tDef
  //   Returns 0 if impossible with gensAvail available
  function minGensToBreak(tDef, offLeft, gensAvail) {
    if (!gensAvail || offLeft <= 0) return 0;
    if (!tDef)                      return 1;
    if (offLeft > tDef)             return 1;
    // Need gen bonus: solve offLeft*(1+0.05*(N-1)) > tDef → N > 1+(tDef/offLeft-1)/0.05
    const n = Math.ceil(1 + (tDef / offLeft - 1) / 0.05);
    return n <= gensAvail ? n : 0;
  }

  function canBreak(tDef, offLeft, gensAvail) {
    return minGensToBreak(tDef, offLeft, gensAvail) > 0;
  }

  // ── Own race/personality offense multiplier ───────────────────────────────
  // Applied when comparing against enemy defense (breakability check).
  // Depletion of offLeft still uses raw tDef — troops sent are real troops.
  const ownRace = (prov.race || '').toLowerCase();
  const ownPers = (prov.sot?.personality || '').toLowerCase();
  const ownOffMult = (RACE_OFF_MULT[ownRace] || 1.0) * (PERSONALITY_OFF_MULT[ownPers] || 1.0);

  // ── NW quality score ───────────────────────────────────────────────────────
  function nwQuality(tNW) {
    if (!aNW || !tNW) return 1;
    const r = aNW / tNW;
    if (r >= 0.90 && r <= 1.10) return 3;
    if (r >= 0.75 && r <= 1.33) return 2;
    return 1;
  }

  // ── KD averages for RKNW ──────────────────────────────────────────────────
  const ownProvs    = S.own?.provinces   || [];
  const eneProvs    = S.enemy?.provinces || [];
  const ownKdAvgNW  = ownProvs.length ? ownProvs.reduce((s,p) => s+(p.networth||0),0) / ownProvs.length : 0;
  const eneKdAvgNW  = eneProvs.length ? eneProvs.reduce((s,p) => s+(p.networth||0),0) / eneProvs.length : 0;

  // ── Estimated TM land gains — delegates to top-level _estimateTMGain ────────
  function estimateTMGains(tNW, tLand, tp) {
    return _estimateTMGain(tNW, tLand, tp, ownLand, aNW, ownKdAvgNW, eneKdAvgNW);
  }

  // ── Collect and classify wave targets ─────────────────────────────────────
  const myName = prov.name;

  const allWaveItems = S.enemy ? S.enemy.provinces
    .filter(p => S.provinces[p.slot]?.wave)
    .map(p => {
      const plan = S.provinces[p.slot];
      return {
        province: {
          slot: '['+p.slot+']', rawSlot: p.slot, name: p.name, race: p.race,
          requiredOps:   plan.requiredOps   || [],
          notes:         plan.notes         || '',
          needsRaze:     plan.needsRaze     || false,
          needsMassacre: plan.needsMassacre || false,
          bloat:         plan.bloat         || false,
        },
        assignedTo:   plan.assignedTo || [],
        wave:         plan.wave,
        waveName:     _waveDisplayName(plan.wave),
        wavePriority: _waveOrder(plan.wave),
      };
    }) : [];

  if (!allWaveItems.length) return { attacks: [], gensHome, attackableGens, ownPop, reason: 'no_targets' };

  // Three buckets: A = mine, B = KD pool, C = other's (skip)
  const myItems   = allWaveItems.filter(t => t.assignedTo.length > 0 && t.assignedTo.includes(myName));
  const poolItems = allWaveItems.filter(t => t.assignedTo.length === 0);
  // items assigned to others (not me, not empty) are intentionally ignored

  // ── Enrich target with intel data ─────────────────────────────────────────
  function enrich(item) {
    const tp    = pd(item.province.slot);
    const tDef  = tp?.calcs?.defPointsSummary?.defPointsHome || 0;
    const tNW   = tp?.networth || 0;
    const tLand = tp?.land || 0;
    const away  = tp?.som?.armiesAway?.length > 0;
    const dAge  = tp?.calcs?.defPointsSummary?.ageSeconds;

    // tDefEff = tDef: the API's defPointsHome is ALREADY the effective defense value.
    // The IS computes it from troops × their unit-stats, with racial bonuses baked in.
    // Applying RACE_DEF_MULT on top would double-count and incorrectly lower the target,
    // telling the attacker to send less offense than the province actually requires.
    // Only own-side offense multipliers (ownOffMult) are needed — see comment above.
    const eRace = (tp?.race || item.province.race || '').toLowerCase();
    const ePers = (tp?.sot?.personality || '').toLowerCase();
    const tDefEff  = tDef;  // raw API value IS the effective value
    const hasDefMod = false;

    // Enemy pop%: same formula as own province — ppa is peasants-only, need total pop.
    // Use component sum if available; fall back to ppa/25*100 if fields absent.
    const _es = tp?.sot || {};
    const _eLand = tp?.land || 0;
    const _eTotalPop = (_es.peasants || 0) + (_es.totalTroops || 0)
                     + (_es.thieves  || 0) + (_es.wizards    || 0);
    const tPop  = _eLand > 0 && _eTotalPop > 0
      ? Math.min(Math.round(_eTotalPop / (_eLand * 25) * 100), 150)
      : _es.ppa != null ? Math.min(Math.round(_es.ppa / 25 * 100), 150) : null;
    const nwQ   = nwQuality(tNW);
    // Breakability uses effective values: our racial/pers off bonus vs their racial/pers def bonus
    const canBr = canBreak(tDefEff, aOff * ownOffMult, attackableGens);
    const gains = estimateTMGains(tNW, tLand, tp);
    return { item, tp, tDef, tDefEff, hasDefMod, eRace, ePers, tNW, tLand, tPop, nwQ, away, breaks: canBr, dAge, gains };
  }

  const myEnriched   = myItems.map(enrich);
  const poolEnriched = poolItems.map(enrich);

  // ── Sort assigned targets: wave priority ASC, tDef ASC within priority ─────
  myEnriched.sort((a, b) => {
    const pa = a.item.wavePriority, pb = b.item.wavePriority;
    return pa !== pb ? pa - pb : a.tDef - b.tDef;
  });

  // ── Sort pool targets: NW quality DESC → breakable DESC → enemy pop% DESC ──
  poolEnriched.sort((a, b) => {
    if (b.nwQ !== a.nwQ) return b.nwQ - a.nwQ;
    const bBr = b.breaks ? 1 : 0, aBr = a.breaks ? 1 : 0;
    if (bBr !== aBr)     return bBr - aBr;
    return (b.tPop || 0) - (a.tPop || 0);
  });

  // ── >100% pop: expand pool to any non-bloat enemy province ──────────────────
  // Order: wave targets in good/optimal NW range first, then all other enemy
  // provinces sorted by NW quality → can break → enemy pop% DESC, then wave
  // targets in marginal range last.
  let activePool = poolEnriched;
  if (ownPop !== null && ownPop > 100 && S.enemy?.provinces) {
    const waveSlotSet = new Set(allWaveItems.map(t => t.province.rawSlot));

    const extraItems = S.enemy.provinces
      .filter(ep => {
        if (waveSlotSet.has(ep.slot)) return false;  // already in wave pool
        const pl = S.provinces[ep.slot];
        if (pl?.bloat) return false;                  // never attack bloat
        // Skip targets assigned to someone else
        if (pl?.assignedTo?.length > 0 && !pl.assignedTo.includes(myName)) return false;
        return true;
      })
      .map(ep => ({
        province: {
          slot: '['+ep.slot+']', rawSlot: ep.slot, name: ep.name, race: ep.race,
          requiredOps: [], notes: '', needsRaze: false, needsMassacre: false, bloat: false,
        },
        assignedTo: (S.provinces[ep.slot]?.assignedTo) || [],
        wave: null,
        waveName: 'Opportunity',
        wavePriority: 999,
      }));

    const extraEnriched = extraItems.map(enrich).sort((a, b) => {
      if (b.nwQ !== a.nwQ) return b.nwQ - a.nwQ;
      const bBr = b.breaks ? 1 : 0, aBr = a.breaks ? 1 : 0;
      if (bBr !== aBr)     return bBr - aBr;
      return (b.tPop || 0) - (a.tPop || 0);
    });

    // Wave targets in good/optimal range come before the extra pool;
    // wave marginal targets are last resort after the extra pool is exhausted.
    const waveGood     = poolEnriched.filter(t => t.nwQ >= 2);
    const waveMarginal = poolEnriched.filter(t => t.nwQ <  2);
    activePool = [...waveGood, ...extraEnriched, ...waveMarginal];
  }

  // ── Attack type per target ─────────────────────────────────────────────────
  // Bloat: never TM — only RAZE or MASS when war leader explicitly flags them.
  // Non-bloat: war leader needsRaze/needsMassacre flag always honoured (single hit).
  // Otherwise TM (pool targets' op type is governed separately by pop% strategy).
  function attackType(enriched) {
    const p = enriched.item.province;
    if (p.bloat) {
      if (p.needsRaze)     return 'RAZE';
      if (p.needsMassacre) return 'MASS';
      return null; // bloat with no action flag → never attack
    }
    // War leader explicit flags always win — regardless of own pop%
    if (p.needsRaze)     return 'RAZE';
    if (p.needsMassacre) return 'MASS';
    return 'TM';
  }

  // ── Pop% strategy for pool targets ────────────────────────────────────────
  // Pool raze/mass: only allowed if pop% < 100%.  >100% = TM focus only.
  // Pool TM limit: pop% < 70% → max 2 TM from pool (prefer raze/mass there)
  const poolRazeAllowed = ownPop === null || ownPop < 100;
  const poolRazeMassMax = (ownPop !== null && ownPop >= 70 && ownPop <= 99) ? 1 : Infinity;
  const poolTMMax       = (ownPop !== null && ownPop < 70) ? 2 : Infinity;

  // ── Attack loop state ─────────────────────────────────────────────────────
  const attacks   = [];
  let gensLeft    = attackableGens;
  let offLeft     = aOff;                 // depleted by (tDef+1) per attack
  let poolTMCount = 0, poolRMCount = 0;
  const hitCount  = {};                   // rawSlot → hit count for SoD reminders

  function addAttack(enriched, isTM, isPool) {
    // Use effective offense (with racial/pers bonus) and effective defense for gen calc.
    // offLeft depletion uses raw tDef — troops physically sent are unchanged by the multiplier.
    const mg = minGensToBreak(enriched.tDefEff, offLeft * ownOffMult, gensLeft);

    // sentOff = minimum raw offense to send to break this target.
    // Game check: sentRaw × ownOffMult × genBonus > tDef
    // → sentRaw = ceil(tDef / (ownOffMult × genBonus)) + 1
    //
    // For a neutral attacker (ownOffMult=1): sentOff = tDef + 1  ← simplest case
    // For Avian (+20% off):  sentOff = ceil(tDef / 1.20) + 1     ← sends fewer raw troops
    // For Elf  (−5% off):   sentOff = ceil(tDef / 0.95) + 1     ← must send slightly more
    const _genBonus = 1 + 0.05 * (mg - 1);
    const sentOff = mg > 0
      ? Math.ceil(enriched.tDef / (ownOffMult * _genBonus)) + 1
      : 0;

    // pct = full remaining offense (before depletion) vs effective defense.
    // Shows the comfort margin — how much more than minimum the player has.
    // Captured here so it correctly decreases across multi-attack sequences.
    const pct = sentOff > 0
      ? Math.round(offLeft * ownOffMult / (enriched.tDefEff || 1) * 100)
      : 0;

    const rs = enriched.item.province.rawSlot;
    hitCount[rs] = (hitCount[rs] || 0) + 1;
    gensLeft     = Math.max(0, gensLeft - mg);
    offLeft      = Math.max(0, offLeft - (enriched.tDef + 1)); // spend minimum needed (raw)
    if (isPool) { if (isTM) poolTMCount++; else poolRMCount++; }
    attacks.push({
      n:          attacks.length + 1,
      target:     enriched,
      gens:       mg,
      sentOff,
      result:     mg > 0 ? 'yes' : 'marginal',
      pct,
      attackType: isTM ? 'TM' : (enriched.item.province.needsRaze ? 'RAZE' : 'MASS'),
      isAssigned: !isPool,
      gains:      isTM ? enriched.gains : null,
      sodNote:    hitCount[rs] > 1
                    ? `Take a fresh SoD on ${enriched.item.province.name} before sending this attack`
                    : null,
      waveName:   enriched.item.waveName,
      tPop:       enriched.tPop,
    });
  }

  // Partition assigned targets: RAZE/MASS (single hit) vs TM (multi-hit)
  const myRM = myEnriched.filter(t => { const at = attackType(t); return at === 'RAZE' || at === 'MASS'; });
  const myTM = myEnriched.filter(t => attackType(t) === 'TM');

  // Pass 1A: assigned RAZE / MASS — single hit each, ordered by wave priority
  for (const t of myRM) {
    if (gensLeft <= 0 || offLeft <= 0) break;
    addAttack(t, false, false);  // single hit; addAttack marks result marginal if can't break
  }

  // Pass 1B: assigned TM — min gens per hit, repeat until can't break or resources gone.
  // Remaining gens/off fall through to the pool pass below.
  for (const t of myTM) {
    if (gensLeft <= 0 || offLeft <= 0) break;
    if (!canBreak(t.tDefEff, offLeft * ownOffMult, gensLeft)) {
      // Assigned but unbreakable — show as warning, don't loop
      addAttack(t, true, false);
      continue;
    }
    // Multi-hit: each iteration uses minimum gens, leaving the rest for another round
    while (gensLeft > 0 && offLeft > 0 && canBreak(t.tDefEff, offLeft * ownOffMult, gensLeft)) {
      addAttack(t, true, false);
    }
  }

  // Pass 2: pool/opportunity targets (spare gens/off, pop% strategy applies)
  for (const t of activePool) {
    if (gensLeft <= 0 || offLeft <= 0) break;
    if (!canBreak(t.tDefEff, offLeft * ownOffMult, gensLeft)) continue; // skip unbreakable
    const aType = attackType(t);
    if (!aType) continue;
    const isTM = aType === 'TM';
    if (!isTM && !poolRazeAllowed) continue;             // >100% pop: skip pool raze/mass
    if (!isTM && poolRMCount >= poolRazeMassMax) continue; // 70-99%: 1 raze/mass max
    if (isTM  && poolTMCount >= poolTMMax)       continue; // <70%: limit TM from pool
    addAttack(t, isTM, true);
  }

  const totalGains = attacks.reduce((s, a) => s + (a.gains || 0), 0);

  return {
    attacks, prov, gensHome, attackableGens,
    gensLeft, offLeft, aOff,
    ownPop, totalGains,
    best: myEnriched[0] || poolEnriched[0] || null,
    armyStatus,
  };
}

/**
 * Max Gain attack planner.
 *
 * Finds the sequence of TM attacks against any non-bloat enemy province that
 * maximises total land gained.  Uses a greedy efficiency-first loop:
 *
 *   1. For each candidate compute: gain / offCost  (acres per offense point)
 *   2. Pick the most efficient province the player can still break
 *   3. Record the attack, update simulated land/NW for that province
 *      (subsequent hits on the same province get correctly smaller estimates)
 *   4. Repeat until gens or offense runs out
 *
 * Returns an object with the same shape as calcAttacks() so the same renderer
 * handles both modes.
 */
function calcMaxGainAttacks(prov) {
  // ── Own stats (mirrors calcAttacks derivation) ────────────────────────────
  const _armiesAway   = prov.som?.armiesAway || [];
  const _overdueCount = _armiesAway.filter(a => a.secondsRemaining != null && a.secondsRemaining <= 0).length;
  const _allOverdue   = _armiesAway.length > 0 && _overdueCount === _armiesAway.length;
  const _sotOff  = prov.sot?.offPoints || 0;
  const _apiOff  = _allOverdue && _sotOff ? _sotOff : (prov.som?.offPointsHome || 0);
  const _sotGens = prov.sot?.generals;
  const _apiGens = _allOverdue && _sotGens != null
    ? _sotGens : (prov.som?.standingArmy?.generals ?? _sotGens ?? 5);

  const aOff     = _eff(prov.name, 'off',  _apiOff);
  const aNW      = _eff(prov.name, 'nw',   prov.networth || 0);
  const gensHome = _eff(prov.name, 'gens', _apiGens);
  const ownLand  = prov.land || prov.sot?.acres || 0;
  const attackableGens = Math.max(0, gensHome - 1);

  const ownRace    = (prov.race || '').toLowerCase();
  const ownPers    = (prov.sot?.personality || '').toLowerCase();
  const ownOffMult = (RACE_OFF_MULT[ownRace] || 1.0) * (PERSONALITY_OFF_MULT[ownPers] || 1.0);

  const ownProvs   = S.own?.provinces   || [];
  const eneProvs   = S.enemy?.provinces || [];
  const ownKdAvgNW = ownProvs.length ? ownProvs.reduce((s,p) => s+(p.networth||0),0) / ownProvs.length : 0;
  const eneKdAvgNW = eneProvs.length ? eneProvs.reduce((s,p) => s+(p.networth||0),0) / eneProvs.length : 0;

  if (!aOff || !attackableGens) {
    return { attacks: [], gensHome, attackableGens, aOff,
             gensLeft: attackableGens, offLeft: aOff, totalGains: 0,
             reason: !aOff ? 'no_off' : 'no_gens' };
  }

  // ── Build candidate pool: all non-bloat enemy provinces we can break ──────
  const candidates = (S.enemy?.provinces || [])
    .filter(ep => !S.provinces[ep.slot]?.bloat)
    .map(ep => {
      const tp    = pd('[' + ep.slot + ']');
      const tDef  = tp?.calcs?.defPointsSummary?.defPointsHome || 0;
      const tNW   = tp?.networth || 0;
      const tLand = tp?.land     || 0;
      const away  = (tp?.som?.armiesAway?.length || 0) > 0;
      const dAge  = tp?.calcs?.defPointsSummary?.ageSeconds;
      if (!tDef || !tLand || aOff * ownOffMult <= tDef) return null;
      const offCost = Math.ceil(tDef / ownOffMult) + 1;
      return { ep, tp, tDef, tNW, tLand, offCost, away, dAge };
    })
    .filter(Boolean);

  if (!candidates.length) {
    return { attacks: [], gensHome, attackableGens, aOff,
             gensLeft: attackableGens, offLeft: aOff, totalGains: 0,
             reason: 'no_targets' };
  }

  // ── Per-province simulated state ─────────────────────────────────────────
  // Gain estimates use simLand/simNW so each hit correctly reflects depleted land.
  const simLand = {}, simNW = {};
  candidates.forEach(c => { simLand[c.ep.slot] = c.tLand; simNW[c.ep.slot] = c.tNW; });

  // ── Greedy loop ──────────────────────────────────────────────────────────
  const attacks   = [];
  const hitCount  = {};
  let offLeft     = aOff;
  let gensLeft    = attackableGens;

  for (let iter = 0; iter < 60 && gensLeft > 0 && offLeft > 0; iter++) {
    let best = null, bestGain = 0, bestEff = -1;

    for (const c of candidates) {
      const sl = simLand[c.ep.slot];
      if (sl <= 0) continue;
      if (offLeft * ownOffMult <= c.tDef || offLeft < c.offCost) continue;

      const gain = _estimateTMGain(simNW[c.ep.slot], sl, c.tp,
                                   ownLand, aNW, ownKdAvgNW, eneKdAvgNW);
      if (!gain || gain <= 0) continue;

      const eff = gain / c.offCost;
      if (eff > bestEff) { best = c; bestGain = gain; bestEff = eff; }
    }

    if (!best) break;

    // Capture pre-hit simulated state for display
    const s          = best.ep.slot;
    const landBefore = simLand[s];
    const nwBefore   = simNW[s];

    // Update simulated state: deduct estimated gain from land and NW
    const nwPerAcre  = landBefore > 0 ? nwBefore / landBefore : 0;
    simLand[s] = Math.max(0, landBefore - bestGain);
    simNW[s]   = Math.max(0, nwBefore   - bestGain * nwPerAcre);

    hitCount[s] = (hitCount[s] || 0) + 1;

    // Build attack object compatible with _buildAttackCard
    const pct = Math.round(offLeft * ownOffMult / best.tDef * 100);
    attacks.push({
      n:       attacks.length + 1,
      target: {
        item: {
          province: {
            slot:          '[' + s + ']',
            rawSlot:       s,
            name:          best.ep.name,
            race:          best.ep.race || '',
            requiredOps:   [],
            notes:         '',
            needsRaze:     false,
            needsMassacre: false,
            bloat:         false,
          },
          waveName:     'Max Gain',
          wavePriority: 1,
        },
        tp:        best.tp,
        tDef:      best.tDef,
        tDefEff:   best.tDef,
        tNW:       nwBefore,
        tLand:     landBefore,
        tPop:      null,
        nwQ:       1,
        away:      best.away,
        dAge:      best.dAge,
        gains:     bestGain,
        hasDefMod: false,
        eRace:     '', ePers: '',
        breaks:    true,
      },
      gens:       1,
      sentOff:    best.offCost,
      result:     'yes',
      pct,
      attackType: 'TM',
      isAssigned: false,
      gains:      bestGain,
      sodNote:    hitCount[s] > 1
                    ? `Take a fresh SoD on ${best.ep.name} before sending this attack`
                    : null,
      waveName:   'Max Gain',
      tPop:       null,
    });

    offLeft  -= best.offCost;
    gensLeft -= 1;
  }

  const totalGains = attacks.reduce((s, a) => s + (a.gains || 0), 0);
  return { attacks, gensHome, attackableGens, aOff,
           gensLeft, offLeft, totalGains, ownPop: null, armyStatus: null };
}

function toggleMaxGain() {
  S.maxGainMode = !S.maxGainMode;
  renderPlayer();
}

function renderPlayer() {
  renderTab('__wpc_player', _buildPlayer);
}

function _buildPlayer() {
  if (!S.own || !S.enemy) return '<div class="watk-noprov">Loading data...</div>';
  if (!S.playerProv)      return _buildProvPicker();

  const prov = S.playerProv;

  // Always run the wave planner for header stats (ownPop, armyStatus, gensHome)
  const wavePlan = calcAttacks(prov);
  const { gensHome, attackableGens, ownPop, armyStatus } = wavePlan;

  // Choose active plan
  const maxGainMode = !!S.maxGainMode;
  const plan        = maxGainMode ? calcMaxGainAttacks(prov) : wavePlan;
  const { attacks, gensLeft, totalGains, reason } = plan;
  const aOff = plan.aOff || wavePlan.aOff;

  const waveTargets = S.enemy ? S.enemy.provinces
    .filter(p => S.provinces[p.slot]?.wave)
    .map(p => {
      const plan = S.provinces[p.slot];
      return {
        province: { slot: '['+p.slot+']', rawSlot: p.slot, name: p.name, race: p.race,
                    requiredOps:   plan.requiredOps   || [],
                    notes:         plan.notes         || '',
                    needsRaze:     plan.needsRaze     || false,
                    needsMassacre: plan.needsMassacre || false,
                    bloat:         plan.bloat         || false,
                    assignedTo:    plan.assignedTo    || [] },
        waveName: _waveDisplayName(plan.wave),
      };
    }) : [];

  // ── Army return banner ───────────────────────────────────────────────────
  // Show before building the header so it appears above the stat inputs.
  let armyBanner = '';
  const ms0 = loadManual(prov.name);
  if (armyStatus?.allOverdue) {
    if (armyStatus.offSrc === 'sot') {
      // Auto-corrected — brief info note only if no manual override
      if (!ms0.off && !ms0.gens) {
        armyBanner = `<div style="margin-bottom:10px;padding:8px 14px;background:#1a2820;border:1px solid #305040;
            border-radius:3px;font-size:17px;color:#60c040;display:flex;align-items:center;gap:8px">
          <span style="font-size:19px">↩</span>
          <span><b>All armies returned</b> — offense and generals updated from SoT data automatically.
          Override the fields below if the SoT is stale.</span>
        </div>`;
      }
    } else {
      // Overdue but no SoT to fall back on — manual entry required
      armyBanner = `<div style="margin-bottom:10px;padding:8px 14px;background:#201808;border:1px solid #805020;
          border-radius:3px;font-size:17px;color:#e09040;display:flex;align-items:center;gap:8px">
        <span style="font-size:19px">⚠</span>
        <span><b>All armies returned but no SoT available.</b>
        Offense data is stale — enter your current max offense in the field below.</span>
      </div>`;
    }
  } else if (armyStatus?.anyOverdue) {
    armyBanner = `<div style="margin-bottom:10px;padding:8px 14px;background:#201808;border:1px solid #805020;
        border-radius:3px;font-size:17px;color:#e09040;display:flex;align-items:center;gap:8px">
      <span style="font-size:19px">⚠</span>
      <span><b>Some armies have returned</b> — generals and offense may be higher than shown.
      Verify your stats or enter current values below.</span>
    </div>`;
  }

  let h = armyBanner + _playerHeader(prov, aOff, gensHome, attackableGens, ownPop, waveTargets.length, armyStatus);

  // Mode toggle bar — always visible once a province is picked
  h += `<div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;">
    <button onclick="__wpA.toggleMaxGain()"
      style="padding:5px 14px;font-size:17px;font-weight:700;cursor:pointer;border-radius:3px;
             background:${maxGainMode ? '#203820' : '#2b3333'};
             border:1px solid ${maxGainMode ? '#60c040' : '#617070'};
             color:${maxGainMode ? '#60c040' : '#7a9090'}">
      ⚡ Max Gain${maxGainMode ? ' ON' : ''}
    </button>
    ${maxGainMode
      ? `<span style="font-size:17px;color:#60c040">Ignoring wave plan — showing best land gain from any target</span>`
      : `<button onclick="__wpA.toggleMaxGain()"
           style="display:none"></button>`
    }
  </div>`;

  // In wave mode: guard against missing data
  if (!maxGainMode) {
    if (!waveTargets.length) {
      return h + `<div class="watk-notarget">// No wave targets assigned yet<br>
        <span style="font-size:17px">The war leader needs to set targets in the WAR BOARD tab first</span></div>`;
    }
    if (reason === 'no_off') {
      return h + `<div class="watk-notarget">// No offensive data available for this province<br>
        <span style="font-size:17px">SoM data needed to calculate attacks</span></div>`;
    }
    if (reason === 'no_gens') {
      return h + `<div class="watk-notarget">// Cannot attack — only 1 general home<br>
        <span style="font-size:17px">At least 2 generals must be home (1 is always kept back)</span></div>`;
    }
  }

  if (reason === 'no_off') {
    return h + `<div class="watk-notarget">// No offensive data available</div>`;
  }
  if (reason === 'no_gens') {
    return h + `<div class="watk-notarget">// Cannot attack — only 1 general home</div>`;
  }
  if (!attacks.length) {
    return h + `<div class="watk-notarget">${maxGainMode
      ? '// No breakable targets with positive TM gains found — check intel age'
      : '// No attack plan generated — check intel age or wait for armies to return'
    }</div>`;
  }

  // Group attacks by wave name
  const byWave = {};
  attacks.forEach(atk => {
    const wn = atk.target.waveName || 'Wave';
    if (!byWave[wn]) byWave[wn] = [];
    byWave[wn].push(atk);
  });

  h += `<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
    <div class="wsech" style="margin-bottom:0">${maxGainMode ? '// ⚡ MAX GAIN PLAN' : '// ATTACK PLAN'}</div>
    ${!maxGainMode ? `<button onclick="__wpA.toggleNWPanel()"
      style="padding:4px 12px;background:#1a2828;border:1px solid #617070;color:#a0d0b0;
             font-size:17px;font-weight:700;cursor:pointer;border-radius:3px"
      title="Open wave target province pages to get real-time NW during a wave">
      ⟳ NW
    </button>` : ''}
  </div>`;
  Object.entries(byWave).forEach(([wave, list]) => {
    h += _buildAttackCard(wave, list);
  });

  // Total estimated TM gains
  if (totalGains > 0) {
    h += `<div style="margin:6px 0 10px;padding:8px 14px;background:#1a2828;border:1px solid #304880;
                      border-radius:3px;font-size:17px;color:#80a8f0;display:flex;align-items:center;gap:10px">
      <span style="font-weight:700">📊 Total estimated TM gains: ~${fK(totalGains)} acres</span>
      <span style="font-size:13px;color:#617070">${maxGainMode
        ? '* gains recalculated per hit · rituals, honor not included'
        : '* rituals, honor not included'}</span>
    </div>`;
  }

  if (gensLeft > 0 && homeOffRemaining > 0) {
    h += `<div style="margin:10px 0;padding:8px 12px;background:#1a2828;border:1px solid #617070;
                      border-radius:3px;font-family:monospace;font-size:17px;color:#7a9090">
      🏠 ${gensLeft} gen${gensLeft > 1 ? 's' : ''} remaining home
      — ${fK(Math.round(homeOffRemaining))} off available for ambush / defense
    </div>`;
  }

  h += _buildContextTable(waveTargets, prov, aOff);
  return h;
}

function _buildProvPicker() {
  return `
    <div style="max-width:480px">
      <div class="wsech">// SELECT YOUR PROVINCE</div>
      <div style="display:grid;gap:8px">
        ${(S.own?.provinces || []).map(p => {
          const off  = p.som?.offPointsHome || p.sot?.offPoints || 0;
          const gens = p.som?.standingArmy?.generals ?? '?';
          return `<div onclick="__wpA.pickProv(${p.slot})"
            style="background:#2b3333;border:1px solid #617070;border-radius:3px;padding:12px 14px;cursor:pointer;
                   display:flex;align-items:center;justify-content:space-between;transition:border-color .15s"
            onmouseover="this.style.borderColor='#617070'" onmouseout="this.style.borderColor='#617070'">
            <div>
              <div style="font-size:21px;font-weight:700">${esc(p.name)}</div>
              <div style="font-family:monospace;font-size:17px;color:#7a9090">${esc(p.race || '')} · ${esc(p.sot?.personality || '')}</div>
            </div>
            <div style="text-align:right">
              <div style="font-family:monospace;font-size:19px;color:#ffd400">${fK(off)} off</div>
              <div style="font-family:monospace;font-size:17px;color:#7a9090">${gens} gens home · ${fK(p.networth)} NW</div>
            </div>
          </div>`;
        }).join('')}
      </div>
    </div>`;
}

function _playerHeader(prov, aOff, gensHome, attackableGens, ownPop, targetCount, armyStatus) {
  const genColor = attackableGens >= 3 ? '#60C040' : attackableGens >= 1 ? '#e09040' : '#E05050';
  const popColor = ownPop === null ? '#7a9090'
                 : ownPop > 100   ? '#60C040'
                 : ownPop >= 70   ? '#ffd400' : '#E05050';
  const popTier  = ownPop === null ? '' : ownPop > 100 ? 'TM focus' : ownPop >= 70 ? 'mixed' : 'raze/mass';
  const ms = loadManual(prov.name);  // single localStorage read for the whole header

  // Source-aware API values — when armies are overdue, use the auto-corrected figures
  const _sotOff  = prov.sot?.offPoints || 0;
  const _apiOff  = (armyStatus?.allOverdue && _sotOff) ? _sotOff : (prov.som?.offPointsHome || 0);
  const _sotGens = prov.sot?.generals;
  const _apiGens = (armyStatus?.allOverdue && _sotGens != null)
    ? _sotGens : (prov.som?.standingArmy?.generals ?? _sotGens ?? 5);

  const apiOff  = _apiOff;
  const apiNW   = prov.networth || 0;
  const apiGens = _apiGens;

  // Hint labels for each input — show data source and auto-correction status
  const offHintRaw  = !ms.off
    ? (armyStatus?.allOverdue && _sotOff ? '<span style="color:#60c040">↩ SoT (army returned)</span>'
    : armyStatus?.offSrc === 'stale'     ? '<span style="color:#e09040">⚠ stale — enter max off</span>'
    : apiOff                             ? 'from SoM' : '')
    : '✎ manual';
  const gensHintRaw = !ms.gens
    ? (armyStatus?.allOverdue && _sotGens != null ? '<span style="color:#60c040">↩ SoT (army returned)</span>'
    : apiGens                                     ? 'from SoM' : '')
    : '✎ manual';

  // Amber border on offense input if overdue and no SoT fallback and no manual override
  const offInputBorder = (!ms.off && armyStatus?.offSrc === 'stale')
    ? '#e09040' : '#617070';
  // Escape province name for safe embedding in both HTML attrs and JS string literals
  const pn = prov.name.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/</g, '&lt;');

  const inputStyle = 'background:#1a2828;border:1px solid #617070;color:#ffffff;font-family:monospace;' +
    'font-size:17px;padding:4px 8px;border-radius:3px;width:100%;box-sizing:border-box;margin-top:3px';
  const offInputStyle = inputStyle.replace('#617070', offInputBorder);
  const hintStyle = 'font-size:13px;color:#7a9090;margin-top:2px';

  return `
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px">
      <div>
        <div style="font-size:21px;font-weight:700">${esc(prov.name)}</div>
        <div style="font-family:monospace;font-size:17px;color:#7a9090">${esc(prov.race || '')} · ${esc(prov.sot?.personality || '')}</div>
      </div>
      <button onclick="__wpA.pickProv('')"
        style="padding:5px 10px;background:#2b3333;border:1px solid #617070;color:#ffffff;font-size:17px;font-weight:700;cursor:pointer;border-radius:3px">
        ↩ Change
      </button>
    </div>

    <div style="background:#1a2828;border:1px solid #617070;border-radius:3px;padding:12px 14px;margin-bottom:14px">
      <div style="font-size:13px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:#7a9090;margin-bottom:10px">
        My Stats — enter your current values (saves on Tab/Enter/click away)
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px">
        <div>
          <div style="font-size:13px;color:#7a9090;font-weight:700;text-transform:uppercase;letter-spacing:1px">Max Offense</div>
          <input type="number" value="${ms.off || apiOff || ''}" placeholder="${apiOff ? fK(apiOff)+' (API)' : 'e.g. 85000'}"
            style="${offInputStyle}"
            onchange="__wpA.setManualStat('${pn}','off',this.value)"
            onkeydown="if(event.key==='Enter')this.blur()">
          <div style="${hintStyle}">${offHintRaw}</div>
        </div>
        <div>
          <div style="font-size:13px;color:#7a9090;font-weight:700;text-transform:uppercase;letter-spacing:1px">Net Worth</div>
          <input type="number" value="${ms.nw || apiNW || ''}" placeholder="${apiNW ? fK(apiNW)+' (API)' : 'e.g. 250000'}"
            style="${inputStyle}"
            onchange="__wpA.setManualStat('${pn}','nw',this.value)"
            onkeydown="if(event.key==='Enter')this.blur()">
          ${ms.nw ? '<div style="'+hintStyle+'">✎ manual</div>' : (apiNW ? '<div style="'+hintStyle+'">from IS</div>' : '')}
        </div>
        <div>
          <div style="font-size:13px;color:#7a9090;font-weight:700;text-transform:uppercase;letter-spacing:1px">Generals</div>
          <input type="number" min="0" max="5" value="${ms.gens != null ? ms.gens : (apiGens || '')}" placeholder="${apiGens || '1-5'}"
            style="${inputStyle}"
            onchange="__wpA.setManualStat('${pn}','gens',this.value)"
            onkeydown="if(event.key==='Enter')this.blur()">
          <div style="${hintStyle}">${gensHintRaw}</div>
        </div>
      </div>
    </div>

    <div class="watk-summary">
      <div class="watk-sstat"><div class="l">Off Home</div><div class="v">${fK(aOff)}</div></div>
      <div class="watk-sstat">
        <div class="l">Generals</div>
        <div class="v" style="color:${genColor}">${attackableGens}<span style="font-size:19px;color:#7a9090"> attack</span></div>
        <div class="s">${gensHome} home · 1 kept</div>
      </div>
      <div class="watk-sstat"><div class="l">Own NW</div><div class="v">${fK(aOff ? (ms.nw || apiNW) : 0)}</div></div>
      ${ownPop !== null ? `<div class="watk-sstat">
        <div class="l">Own Pop%</div>
        <div class="v" style="color:${popColor}">${ownPop}%</div>
        <div class="s">${popTier}</div>
      </div>` : ''}
      <div class="watk-sstat"><div class="l">Wave Targets</div><div class="v">${targetCount}</div><div class="s">by war leader</div></div>
    </div>`;
}

function _buildAttackCard(wave, atkList) {
  let h = `
    <div class="watk-card">
      <div class="watk-header">
        <span class="watk-wave">// ${esc(wave.toUpperCase())}</span>
        <span style="font-family:monospace;font-size:17px;color:#7a9090">${atkList.length} attack${atkList.length > 1 ? 's' : ''}</span>
      </div>
      <div class="watk-body">`;

  const claims = loadClaims();

  atkList.forEach(atk => {
    const t         = atk.target;
    const away      = t.tp?.som?.armiesAway?.length > 0;
    const ops       = t.item.province.requiredOps || [];
    const da        = t.dAge;
    const genColor  = atk.gens <= 2 ? '#60C040' : atk.gens <= 3 ? '#e09040' : '#ffffff';
    const resCls    = atk.result === 'yes' ? 'watk-yes' : atk.result === 'close' ? 'watk-cl' : 'watk-no';
    const resLabel  = atk.result === 'yes' ? 'BREAKS' : atk.result === 'close' ? 'CLOSE' : 'RISKY';
    const sentOff   = atk.sentOff || 0;
    const rs        = t.item.province.rawSlot;
    const razeClaim = claims['raze_'     + rs];
    const massClaim = claims['massacre_' + rs];

    // Attack type badge
    const typeBadge = atk.attackType === 'RAZE' ? '<span class="watk-type watk-type-rz">Raze</span>'
                    : atk.attackType === 'MASS' ? '<span class="watk-type watk-type-ms">Mass</span>'
                    : '<span class="watk-type watk-type-tm">TM</span>';
    // Source badge
    const srcBadge = atk.isAssigned
      ? '<span class="watk-src watk-src-a">Assigned</span>'
      : '<span class="watk-src watk-src-p">KD pool</span>';
    // Gains line (TM only)
    const gainsNote = atk.gains != null && atk.gains > 0
      ? `<span style="color:#80a8f0">~${fK(atk.gains)} acres (est.)</span>`
      : atk.gains === 0 ? '<span style="color:#617070">~0 acres (NW out of range)</span>' : '';
    // Enemy pop% for pool targets
    const tPopNote = !atk.isAssigned && atk.tPop != null
      ? `<span style="color:#7a9090">enemy pop ${atk.tPop}%</span>` : '';

    h += `
      <div class="watk-row">
        <div class="watk-num" style="color:#7a9090">${atk.n}</div>
        <div class="watk-main">
          <div class="watk-target" style="display:flex;align-items:center;flex-wrap:wrap;gap:6px">
            <span>${esc(t.item.province.name)}</span>
            ${typeBadge}${srcBadge}
            ${away ? '<span style="color:#60C040;font-size:17px">↗ army away</span>' : ''}
          </div>
          <div class="watk-detail">
            ${fK(t.tDef)} def · ${fK(sentOff)} off sent · ${atk.pct}% ratio
            ${da != null ? ` · intel <span class="${aC(da)}">${fA(da)}</span> old` : ''}
            ${gainsNote ? ` · ${gainsNote}` : ''}
            ${tPopNote  ? ` · ${tPopNote}`  : ''}
            ${atk.note    ? `<br><span style="color:#e09040">⚠ ${esc(atk.note)}</span>` : ''}
            ${atk.sodNote ? `<br><span style="color:#ffd400;font-weight:700">⚠ ${esc(atk.sodNote)}</span>` : ''}
          </div>
          ${ops.length ? `<div class="watk-ops">${ops.map(o => `<span class="wtag" style="cursor:default">${o}</span>`).join('')}</div>` : ''}
          ${t.item.province.notes ? `<div style="margin-top:4px;font-size:17px;color:#ffffff;background:#2b3333;padding:4px 6px;border-radius:2px;border-left:2px solid #ffd400">${esc(t.item.province.notes)}</div>` : ''}
          ${t.item.province.needsRaze ? `
          <div class="watk-task${razeClaim ? ' claimed' : ''}">
            <span>🔥</span>
            <span style="font-weight:700;color:${razeClaim ? '#ffd400' : '#E05050'}">${razeClaim ? 'RAZE — you claimed this' : 'RAZE NEEDED'}</span>
            <label class="watk-claim">
              <input type="checkbox" ${razeClaim ? 'checked' : ''} onchange="__wpA.claimAction(${rs},'raze')"
                style="cursor:pointer;width:14px;height:14px;accent-color:#ffd400">
              <span style="font-size:17px;color:${razeClaim ? '#ffd400' : '#7a9090'}">${razeClaim ? 'unclaim' : 'claim'}</span>
            </label>
          </div>` : ''}
          ${t.item.province.needsMassacre ? `
          <div class="watk-task${massClaim ? ' claimed' : ''}">
            <span>💀</span>
            <span style="font-weight:700;color:${massClaim ? '#ffd400' : '#E05050'}">${massClaim ? 'MASSACRE — you claimed this' : 'MASSACRE NEEDED'}</span>
            <label class="watk-claim">
              <input type="checkbox" ${massClaim ? 'checked' : ''} onchange="__wpA.claimAction(${rs},'massacre')"
                style="cursor:pointer;width:14px;height:14px;accent-color:#ffd400">
              <span style="font-size:17px;color:${massClaim ? '#ffd400' : '#7a9090'}">${massClaim ? 'unclaim' : 'claim'}</span>
            </label>
          </div>` : ''}
        </div>
        <div class="watk-gen">
          <div class="watk-gen-num" style="color:${genColor}">${atk.gens}</div>
          <div class="watk-gen-label">generals</div>
        </div>
        <div class="watk-result ${resCls}">${resLabel}<br>${atk.pct}%</div>
      </div>`;
  });

  h += '</div></div>';
  return h;
}

function _buildContextTable(waveTargets, prov, aOff) {
  // Use effective NW (manual override wins over API) for range check — same as calcAttacks()
  const aNW = _eff(prov.name, 'nw', prov.networth || 0);
  const ctxClaims = loadClaims();
  const thStyle   = 'text-align:left;padding:5px 8px;font-size:15px;font-weight:700;color:#7a9090;letter-spacing:1px;text-transform:uppercase;border-bottom:1px solid #617070';

  const rows = waveTargets.map(item => {
    const tp    = pd(item.province.slot);
    const tDef  = tp?.calcs?.defPointsSummary?.defPointsHome || 0;
    const tNW   = tp?.networth || 0;
    const away  = tp?.som?.armiesAway?.length > 0;
    // NW quality (no hard cutoff — any target is hittable)
    const nwQ   = (!aNW || !tNW) ? 1
                : (() => { const r = aNW / tNW; return r >= 0.90 && r <= 1.10 ? 3 : r >= 0.75 && r <= 1.33 ? 2 : 1; })();
    const nwLabel = nwQ === 3 ? '✓ optimal' : nwQ === 2 ? '✓ good' : '~ marginal';
    const nwCls   = nwQ === 3 ? 'wmyes' : nwQ === 2 ? 'wmyes' : 'wmcl';
    const pct   = tDef > 0 && aOff > 0 ? Math.round(aOff / tDef * 100) : 0;
    const breaksCls = !aOff || !tDef ? 'wmcl' : aOff > tDef * 1.01 ? 'wmyes' : 'wmno';
    const rs    = item.province.rawSlot;
    const razeClaim = ctxClaims['raze_' + rs];
    const massClaim = ctxClaims['massacre_' + rs];
    const taskHtml  = [
      item.province.needsRaze     ? `<span style="color:${razeClaim?'#ffd400':'#E05050'};font-weight:700">🔥${razeClaim?' ✓':''}</span>` : '',
      item.province.needsMassacre ? `<span style="color:${massClaim?'#ffd400':'#E05050'};font-weight:700">💀${massClaim?' ✓':''}</span>` : '',
    ].filter(Boolean).join(' ') || '—';
    // Bloat / assigned metadata
    const bloat    = item.province.bloat;
    const assigned = item.province.assignedTo || [];
    const assignHtml = assigned.length === 0
      ? '<span style="color:#617070;font-size:15px">KD pool</span>'
      : assigned.map(n => `<span class="wtag" style="font-size:13px;margin:1px;cursor:default">${esc(n)}</span>`).join('');
    const bloatHtml = bloat
      ? '<span style="color:#9060c0;font-size:17px;font-weight:700">● Bloat</span>'
      : '—';

    return `<tr style="border-bottom:1px solid #617070${bloat?';background:rgba(100,60,130,.06)':''}">
      <td style="padding:6px 8px;font-weight:600">${esc(item.province.name)}</td>
      <td style="padding:6px 8px;font-family:monospace">${fK(tDef)}</td>
      <td style="padding:6px 8px;font-family:monospace">${fK(tNW)}</td>
      <td style="padding:6px 8px"><span class="wmatch ${breaksCls}">${pct}%</span></td>
      <td style="padding:6px 8px"><span class="wmatch ${nwCls}">${nwLabel}</span></td>
      <td style="padding:6px 8px">${away ? '<span style="color:#60C040;font-family:monospace;font-size:17px">AWAY</span>' : '—'}</td>
      <td style="padding:6px 8px">${taskHtml}</td>
      <td style="padding:6px 8px">${assignHtml}</td>
      <td style="padding:6px 8px">${bloatHtml}</td>
    </tr>`;
  }).join('');

  return `
    <div style="margin-top:20px" class="wsech">// ALL WAVE TARGETS (context)</div>
    <table style="width:100%;border-collapse:collapse;font-size:17px">
      <thead><tr>
        <th style="${thStyle}">Province</th>
        <th style="${thStyle}">Def Home</th>
        <th style="${thStyle}">NW</th>
        <th style="${thStyle}">Off/Def</th>
        <th style="${thStyle}">NW Range</th>
        <th style="${thStyle}">Army</th>
        <th style="${thStyle}">Task</th>
        <th style="${thStyle}">Assigned</th>
        <th style="${thStyle}">Bloat</th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>`;
}

function pickProv(slot) {
  if (!slot) { S.playerProv = null; renderPlayer(); return; }
  S.playerProv = S.own.provinces.find(p => p.slot === parseInt(slot)) || null;
  renderPlayer();
}


// ═══ tabs/summary.js ═══
// ── TAB: SUMMARY ───────────────────────────────────────────────────────────

function renderSummary() {
  renderTab('__wpc_summary', _buildSummary);
}

function _buildSummary() {
  if (!S.own || !S.enemy) return '';

  const waveTargets = S.enemy ? S.enemy.provinces
    .filter(p => S.provinces[p.slot]?.wave)
    .map(p => ({
      province: { slot: '['+p.slot+']', name: p.name, race: p.race,
                  requiredOps: S.provinces[p.slot]?.requiredOps || [],
                  notes: S.provinces[p.slot]?.notes || '' },
    })) : [];
  const unassigned = S.enemy ? S.enemy.provinces.filter(p => !S.provinces[p.slot]?.wave).length : 0;
  const attackers   = S.own.provinces.filter(p => (p.som?.offPointsHome || 0) > 0);
  const totalOff    = attackers.reduce((s, p) => s + (p.som?.offPointsHome || 0), 0);
  const totalDef    = S.enemy.provinces.reduce((s, p) => s + (p.calcs?.defPointsSummary?.defPointsHome || 0), 0);

  const summaryCards = `
    <div class="wsum">
      <div class="wscard"><div class="l">Targets</div><div class="v">${waveTargets.length}</div><div class="s">${unassigned} unassigned</div></div>
      <div class="wscard"><div class="l">Attackers</div><div class="v">${attackers.length}</div><div class="s">with SoM data</div></div>
      <div class="wscard"><div class="l">Total Off</div><div class="v">${fK(totalOff)}</div></div>
      <div class="wscard"><div class="l">Enemy Def</div><div class="v">${fK(totalDef)}</div><div class="s">known</div></div>
    </div>`;

  const rows = waveTargets.map(item => {
    const p     = pd(item.province.slot);
    const def   = p?.calcs?.defPointsSummary?.defPointsHome || 0;
    const da    = p?.calcs?.defPointsSummary?.ageSeconds;
    const ops   = item.province.requiredOps || [];
    const away  = p?.som?.armiesAway?.length > 0;
    const brk   = attackers.filter(a => canHit(a.networth, p?.networth || 1) && (a.som?.offPointsHome || 0) > def * 1.01).length;
    const pct   = attackers.length > 0 ? Math.round(brk / attackers.length * 100) : 0;
    const pctColor = pct >= 50 ? '#60C040' : pct > 0 ? '#e09040' : '#E05050';

    return `<tr>
      <td style="font-weight:700">${esc(item.province.name)}</td>
      <td style="color:#7a9090">${esc(item.province.race || '')}</td>
      <td>${fK(def)}</td>
      <td>${ops.map(o => `<span class="wtag" style="cursor:default;font-size:15px">${o}</span>`).join('') || '—'}</td>
      <td>${brk}/${attackers.length} <span style="color:${pctColor}">(${pct}%)</span></td>
      <td><span class="${aC(da)}">${fA(da)}</span></td>
      <td>${away ? '<span style="color:#60C040">AWAY</span>' : '—'}</td>
    </tr>`;
  }).join('');

  return `${summaryCards}
    ${sectionHead('Target Coverage')}
    <table class="wtbl">
      <thead><tr>
        <th>Province</th><th>Race</th><th>Def Home</th>
        <th>Ops</th><th>Breakers</th><th>Intel</th><th>Army</th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>`;
}


